window.allTests = window.allTests || {};

window.allTests["test_u2_genel_1"] = [
    {
        soru: "<i>\"Osmanlı Devleti'nin yükselişi, bir gazi ideolojisinin ürünüdür. Osman Bey ve halefleri kendilerini İslam'ın sınırlarını genişletmekle yükümlü gazi savaşçılar olarak tanımlamıştır. Bu ideoloji, erken Osmanlı toplumunu hem siyasi hem de askeri açıdan bir arada tutan temel unsur olmuştur.\"</i><br><br><b>Wittek'in yukarıdaki değerlendirmesine göre Osmanlı Devleti'nin kuruluşundaki en belirleyici etken nedir?</b>",
        secenekler: [
            "A) Bizans İmparatorluğu'nun siyasi çöküşünün yarattığı otorite boşluğu",
            "B) Gazi ideolojisinin Osmanlı toplumunu birleştiren ve yönlendiren temel güç olması",
            "C) Moğol baskısından kaçan Türkmen boylarının yoğun göç dalgası",
            "D) İpek Yolu üzerindeki ticaret gelirlerinin sağladığı ekonomik avantaj",
            "E) Selçuklu Devleti'nden miras alınan güçlü bürokratik yapı"
        ],
        cevap: "B) Gazi ideolojisinin Osmanlı toplumunu birleştiren ve yönlendiren temel güç olması",
        aciklama: "Wittek, Osmanlı Devleti'nin kuruluşunu ve genişlemesini 'gaza' fikrinin (din adına savaş) yarattığı motivasyona ve bu ideolojinin sağladığı toplumsal bütünlüğe bağlar."
    },
    {
        soru: "<i>\"Erken Osmanlı toplumu, katı etnik sınırlara dayanmıyordu. Aksine, Bizans sınırındaki uç bölgesi, farklı inanç ve kökenlerden gelen insanların (Müslümanlar, Hristiyanlar, dönmeler) bir arada hareket edebildiği esnek bir sosyal ortam sunuyordu. Bu geçirgenlik, Osmanlı beyliğinin insan kaynağını hızla genişletmesini sağlamıştır.\"</i><br><br><b>Kafadar'ın bu analizinden hareketle erken Osmanlı dönemi hakkında hangisi söylenebilir?</b>",
        secenekler: [
            "A) Toplumun tamamen homojen bir Türk kimliğine sahip olduğu",
            "B) Sınır bölgesindeki esnek sosyal yapının devletin büyümesini kolaylaştırdığı",
            "C) Din değiştirmenin zorunlu bir devlet politikası olarak uygulandığı",
            "D) Hristiyan tebaanın yönetim kademelerinden tamamen dışlandığı",
            "E) Askeri gücün yalnızca göçebe Türkmen aşiretlerinden oluştuğu"
        ],
        cevap: "B) Sınır bölgesindeki esnek sosyal yapının devletin büyümesini kolaylaştırdığı",
        aciklama: "Kafadar, kuruluşun başarısını sınır bölgesinin (uç) sunduğu esnek, kapsayıcı ve pragmatik sosyal dokuya; farklı kesimlerin devlete entegre edilebilmesine bağlar."
    },
    {
        soru: "<i>\"Osmanlı Beyliği'nin coğrafi konumu, diğer Anadolu beyliklerine kıyasla ona stratejik bir üstünlük sağlamıştır. Bizans ile olan sınır hattı, hem sürekli bir gaza meşruiyeti sunuyor hem de rakip Müslüman beyliklerle erken aşamada çatışmaya girmeden genişleme imkânı tanıyordu.\"</i><br><br><b>Bu metne göre Osmanlı Beyliği'nin konumunun sağladığı temel avantaj aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Selçuklu başkenti Konya'ya yakınlığı sayesinde merkezi destek alması",
            "B) Deniz ticareti yolları üzerinde bulunarak ekonomik zenginlik elde etmesi",
            "C) Bizans sınırında olması sayesinde hem meşruiyet kazanması hem de çatışmasız genişleme alanı bulması",
            "D) Moğol saldırılarından tamamen korunmuş izole bir bölgede yer alması",
            "E) Anadolu'daki diğer Türkmen boyları üzerinde mutlak otorite kurması"
        ],
        cevap: "C) Bizans sınırında olması sayesinde hem meşruiyet kazanması hem de çatışmasız genişleme alanı bulması",
        aciklama: "Beyliğin Bizans sınırında (uçta) yer alması, ona hem 'gaza' yapan kutsal savaşçı imajı kazandırmış hem de diğer beyliklerle iç savaşa girmeden batıya doğru büyüme alanı açmıştır."
    },
    {
        soru: "<i>\"1302 Bapheus (Koyunhisar) Savaşı, Osmanlı askeri gücünün Bizans merkezi ordusu karşısındaki ilk büyük sınavıydı. Bu zafer, Osman Bey'in adını tüm bölgeye duyururken, beyliğin sadece yerel bir aşiret gücü olmadığını, Bizans'ı tehdit edebilecek siyasi bir özneye dönüştüğünü kanıtladı.\"</i><br><br><b>İnalcık'ın bu tespitine göre Bapheus Savaşı'nın Osmanlı tarihi açısından en önemli sonucu nedir?</b>",
        secenekler: [
            "A) Anadolu Selçuklu Devleti'nin resmen sona ermesi",
            "B) Osmanlı Beyliği'nin bölgesel bir siyasi güç olarak meşruiyet kazanması ve tanınması",
            "C) İstanbul'un fethi için gerekli olan donanmanın kurulması",
            "D) Türkmen boylarının Osmanlı'ya karşı birleşerek direniş başlatması",
            "E) Haçlı Seferleri'nin tamamen durdurulması"
        ],
        cevap: "B) Osmanlı Beyliği'nin bölgesel bir siyasi güç olarak meşruiyet kazanması ve tanınması",
        aciklama: "İnalcık'a göre bu savaş, Osmanlı'nın kuruluşunun (devletleşme sürecinin) askeri ve siyasi açıdan tescil edildiği, Bizans karşısında bağımsız bir aktör olarak sivrildiği dönüm noktasıdır."
    },
    {
        soru: "<i>\"Osmanlı idari yapısının kökenleri incelendiğinde, Selçuklu ve İlhanlı bürokratik geleneklerinin derin etkileri görülür. İlk Osmanlı kadıları ve bürokratları genellikle bu köklü merkezlerden gelmiş, devlet teşkilatının profesyonelleşmesini sağlamışlardır. Bu durum, Osmanlı'nın sıfırdan değil, bir miras üzerinde yükseldiğini gösterir.\"</i><br><br><b>Köprülü'nün bu yaklaşımı Osmanlı Devleti'nin kurumsal gelişimi hakkında hangisini destekler?</b>",
        secenekler: [
            "A) Osmanlı kurumlarının tamamen Bizans modelinden kopyalandığını",
            "B) Devlet teşkilatının oluşumunda Türk-İslam medeniyet birikiminin sürekliliğini",
            "C) Göçebe aşiret geleneklerinin bürokraside tek belirleyici olduğunu",
            "D) Osmanlıların yerleşik devlet düzenine ancak İstanbul'un fethinden sonra geçtiğini",
            "E) Eğitim sisteminin tamamen askeri ihtiyaçlara göre şekillendiğini"
        ],
        cevap: "B) Devlet teşkilatının oluşumunda Türk-İslam medeniyet birikiminin sürekliliğini",
        aciklama: "Köprülü, Osmanlı'nın başarısını Orta Asya, Selçuklu ve İslam medeniyetlerinden tevarüs edilen kurumsal ve kültürel mirasın (sürekliliğin) yeni bir bağlamda yeniden üretilmesine bağlar."
    },
    {
        soru: "<i>\"Fethedilen bölgelerde uygulanan 'istimalet' (hoşgörü) politikası, Osmanlı'nın Balkanlardaki kalıcılığının en büyük güvencesi olmuştur. Yerel halkın dinine, geleneklerine ve mülkiyetine saygı gösterilmesi, Bizans'ın ağır vergilerinden bunalan köylülerin Osmanlı idaresini benimsemesini sağlamıştır.\"</i><br><br><b>Metne göre istimalet politikasının fethin başarısındaki rolü nedir?</b>",
        secenekler: [
            "A) Bölgeyi tamamen insansızlaştırarak yeni yerleşim alanları açmak",
            "B) Yerel halkın rızasını kazanarak askeri fethi toplumsal bir kabule dönüştürmek",
            "C) Hristiyan krallıklarla yapılacak savaşlar için zorunlu asker toplamak",
            "D) Balkanların demografik yapısını kısa sürede tamamen değiştirmek",
            "E) Tüm dini yapıları hazineye gelir sağlamak amacıyla kamulaştırmak"
        ],
        cevap: "B) Yerel halkın rızasını kazanarak askeri fethi toplumsal bir kabule dönüştürmek",
        aciklama: "İstimalet, 'meyil ettirme' anlamına gelir. Adalet ve dini özgürlük sunarak fethedilen halkın devlete bağlılığını sağlamayı ve yönetimi kolaylaştırmayı amaçlayan stratejik bir tercihtir."
    },
    {
        soru: "<i>\"Tımar sistemi, Osmanlı askeri ve mali düzeninin belkemiğidir. Bu sistem sayesinde devlet, hazineden para harcamadan taşrada her an savaşa hazır bir süvari ordusu (cebelü) bulundururken aynı zamanda tarımsal üretimin sürekliliğini ve bölge güvenliğini de garanti altına almıştır.\"</i><br><br><b>Tımar sisteminin Osmanlı devlet yapısına sağladığı çok yönlü fayda hangisidir?</b>",
        secenekler: [
            "A) Ticaret yollarını devlet tekelinde toplayarak gümrük gelirlerini artırmak",
            "B) Merkezi orduyu sadece devşirme kökenli askerlerden oluşturmak",
            "C) Askeri, ekonomik ve idari ihtiyaçları tek bir toprak organizasyonuyla çözmek",
            "D) Şehirlerde yaşayan nüfusu köylere göç etmeye zorlayarak üretimi artırmak",
            "E) Padişahın yetkilerini yerel beylerle paylaşarak demokratik bir düzen kurmak"
        ],
        cevap: "C) Askeri, ekonomik ve idari ihtiyaçları tek bir toprak organizasyonuyla çözmek",
        aciklama: "Tımar; ordunun beslenmesi (askeri), toprağın işlenmesi (ekonomik) ve asayişin sağlanması (idari) işlevlerini bütünleştiren rasyonel bir yönetim modelidir."
    },
    {
        soru: "<i>\"Yeniçeri Ocağı'nın kurulması ve devşirme sisteminin uygulanması, Osmanlı merkeziyetçiliğinin zirvesini temsil eder. Aşiret bağları olmayan, doğrudan padişaha bağlı bu profesyonel ordu, sultanın yerel güç odakları ve rakip hanedan üyeleri karşısındaki en büyük kozu olmuştur.\"</i><br><br><b>Bu bilgiye dayanarak Yeniçeri Ocağı'nın kurulmasındaki temel siyasi amaç nedir?</b>",
        secenekler: [
            "A) Türkmen beylerinin ordu üzerindeki etkisini artırmak",
            "B) Padişahın mutlak otoritesini sarsılmaz bir askeri desteğe dayandırmak",
            "C) Balkanlardaki Hristiyan nüfusu askeri yolla tamamen asimile etmek",
            "D) Ordu harcamalarını tamamen ganimet gelirleriyle karşılamak",
            "E) Avrupa devletleriyle diplomatik ilişkileri askeri güçle yürütmek"
        ],
        cevap: "B) Padişahın mutlak otoritesini sarsılmaz bir askeri desteğe dayandırmak",
        aciklama: "Kapıkulu ordusu, yerel ve etnik bağlardan arındırılmış olmasıyla sadece sultana sadakat gösteren bir 'kul' sistemidir ve merkezi otoriteyi rakiplerine karşı korur."
    },
    {
        soru: "<i>\"1402 Ankara Savaşı'nda I. Bayezid'in Timur'a yenilmesiyle başlayan Fetret Devri, Osmanlı Devleti'nin dağılma tehlikesi yaşadığı bir kriz dönemiydi. Ancak devletin bürokratik hafızasının ve tımar düzeninin Rumeli'de işlemeye devam etmesi, hanedanın tekrar birleşmesini mümkün kılmıştır.\"</i><br><br><b>Metne göre Osmanlı'nın Fetret Devri'ni atlatarak yeniden toparlanmasında etkili olan faktör nedir?</b>",
        secenekler: [
            "A) Timur'un Osmanlı topraklarını kardeşler arasında adilce paylaştırması",
            "B) Kurumsal yapının ve idari sistemin kriz anında dahi varlığını koruması",
            "C) Bizans İmparatorluğu'nun bu dönemde Osmanlı'ya askeri destek vermesi",
            "D) Anadolu beyliklerinin Osmanlı'nın yeniden kurulması için iş birliği yapması",
            "E) Padişahın otoritesinin halk tarafından tartışmasız kabul edilmesi"
        ],
        cevap: "B) Kurumsal yapının ve idari sistemin kriz anında dahi varlığını koruması",
        aciklama: "Siyasi otorite parçalanmış olsa da, yerel idari mekanizmaların (tımar, kadı sicilleri, vergi kayıtları) çalışmaya devam etmesi devletin kurumsal bir iskelet üzerinde yükseldiğini kanıtlar."
    },
    {
        soru: "<i>\"Osmanlı hukukunda ferman ve kanunnamelerle düzenlenen 'örfi hukuk', şeriatın (dini hukuk) boş bıraktığı idari, mali ve cezai alanları sultanın otoritesiyle tamamlıyordu. Bu durum, Osmanlı sisteminin değişen koşullara uyum sağlamasını ve pragmatik kararlar alabilmesini kolaylaştırmıştır.\"</i><br><br><b>Osmanlı hukuk sistemindeki 'örfi hukuk'un işlevi hangisidir?</b>",
        secenekler: [
            "A) Şeriat hükümlerini tamamen geçersiz kılarak laik bir düzen kurmak",
            "B) Devlet yönetimine ve güncel ihtiyaçlara dair esnek ve kurumsal çözümler üretmek",
            "C) Yalnızca gayrimüslim tebaanın kendi arasındaki davaları çözmek",
            "D) Padişahın yetkilerini ulemanın denetimine bırakmak",
            "E) Hukuki kararların sadece yerel geleneklere göre verilmesini sağlamak"
        ],
        cevap: "B) Devlet yönetimine ve güncel ihtiyaçlara dair esnek ve kurumsal çözümler üretmek",
        aciklama: "Örfi hukuk, sultanın yasama yetkisini kullanarak devletin karmaşık idari işleyişini, askeri nizamı ve vergi düzenini pratik ihtiyaçlara göre şekillendirmesine olanak tanır."
    },
    {
        soru: "<i>\"Anadolu Selçuklu Devleti'nin Moğol vassallığına girmesi (1243 Kösedağ), batıdaki uç bölgelerinde büyük bir Türkmen nüfusu birikmesine yol açtı. Bu demografik baskı, Bizans'ın zayıf savunma hattını kıran temel dinamikti. Osmanlı bu kitlesel enerjiyi organize edebilen bir siyasi irade olarak öne çıktı.\"</i><br><br><b>Bu metin Osmanlı'nın kuruluşunu hangi perspektifle açıklar?</b>",
        secenekler: [
            "A) Salt askeri dâhilik ve taktik üstünlük",
            "B) Moğol baskısının tetiklediği demografik birikim ve sınır dinamikleri",
            "C) İslam dünyasının halifelik aracılığıyla sağladığı manevi destek",
            "D) Bizans sarayındaki taht kavgalarının yarattığı anlık fırsatlar",
            "E) İpek Yolu'nun kontrolünün sağladığı mutlak mali güç"
        ],
        cevap: "B) Moğol baskısının tetiklediği demografik birikim ve sınır dinamikleri",
        aciklama: "Metin, Selçuklu'nun çöküşüyle sınırda toplanan insan gücünü (demografik baskı) ve bu gücün fetihlere yönlendirilmesini merkeze alır."
    },
    {
        soru: "<i>\"Osmanlı'nın Balkanlardaki 'İskân' politikası, sadece bir nüfus transferi değil, aynı zamanda fethedilen topraklarda Türk-İslam kültürünü kalıcı kılan mekânsal bir dönüşümdü. Vakıflar aracılığıyla inşa edilen cami, medrese ve hamamlar; bozkır geleneklerini kentsel bir medeniyet nizamına bağlamıştır.\"</i><br><br><b>İskân politikasının mimari ve kültürel boyutu hakkında hangisi söylenebilir?</b>",
        secenekler: [
            "A) Mimari yapıların yalnızca askeri kışla işlevi gördüğü",
            "B) Vakıf kurumlarının devlet kontrolü dışında tamamen bağımsız çalıştığı",
            "C) Fiziksel yapıların fethi kalıcı bir kültürel yerleşime dönüştürdüğü",
            "D) İskânın yalnızca Anadolu'daki nüfusu azaltmak için yapıldığı",
            "E) Balkanlardaki yerel mimari geleneğin tamamen yok edildiği"
        ],
        cevap: "C) Fiziksel yapıların fethi kalıcı bir kültürel yerleşime dönüştürdüğü",
        aciklama: "İskân bölgelerine inşa edilen hayır kurumları ve eğitim binaları, bölgenin sosyal çehresini değiştirerek Osmanlı egemenliğini kurumsallaştırmıştır."
    },
    {
        soru: "<i>\"Osmanlı eğitim sisteminin çekirdeği olan medreseler, liyakat ve hiyerarşi üzerine kuruluydu. Talebe, muîd (asistan) ve müderris zinciri içinde bilgi aktarılırken, mezunların 'kadı' veya 'müftü' olarak bürokrasiye girmesi, ilmin devlet yönetimine nüfuz etmesini sağlamıştır.\"</i><br><br><b>Bu metne göre medrese eğitimi ile devlet yönetimi arasındaki ilişki nasıldır?</b>",
        secenekler: [
            "A) Medreseler devletten tamamen bağımsız eleştirel bir alan oluşturmuştur",
            "B) Eğitim sistemi devletin ihtiyaç duyduğu idari ve hukuki kadroları yetiştirmiştir",
            "C) Padişahlar medrese müfredatına müdahale etmekten kaçınmışlardır",
            "D) Sadece askeri sınıfa mensup olanlar medreselerde eğitim alabilmiştir",
            "E) Medrese mezunlarının siyasi görev alması yasaklanmıştır"
        ],
        cevap: "B) Eğitim sistemi devletin ihtiyaç duyduğu idari ve hukuki kadroları yetiştirmiştir",
        aciklama: "Medreseler, ilmiye sınıfını yetiştirerek yargı (kadı) ve din/fetva (müftü) işlerinin ehliyetli ellerle yürütülmesini; dolayısıyla devletin idari kalitesini sağlar."
    },
    {
        soru: "<i>\"Osmanlılarda darüşşifalar (hastaneler) vakıf sistemiyle yönetilir ve buralarda din, dil, ırk ayrımı gözetilmeksizin tüm hastalara ücretsiz bakılırdı. Tıbbi tedavinin yanında müzik ve su sesiyle yapılan psikolojik sağaltım, dönemin tıp anlayışının ne kadar ileri olduğunu gösterir.\"</i><br><br><b>Darüşşifalar hakkındaki bu bilgi hangisini kanıtlar?</b>",
        secenekler: [
            "A) Sağlık hizmetlerinin yalnızca Müslüman tebaaya özel olduğunu",
            "B) Sosyal devlet anlayışının evrensel ve bütüncül bir yaklaşımla uygulandığını",
            "C) Tıp biliminin yalnızca dini metinlerin tekrarından ibaret kaldığını",
            "D) Devletin sağlık harcamalarını karşılayamadığı için vakıflara devrettiğini",
            "E) Psikolojik rahatsızlıkların bilimsel bir sorun olarak görülmediğini"
        ],
        cevap: "B) Sosyal devlet anlayışının evrensel ve bütüncül bir yaklaşımla uygulandığını",
        aciklama: "Ayrım gözetmeksizin ücretsiz hizmet verilmesi sosyal adaleti; ruh ve bedeni birlikte iyileştirme çabası ise tıp bilimindeki bütüncül seviyeyi gösterir."
    },
    {
        soru: "<i>\"Ahi teşkilatı, şehir ekonomisini denetleyen ve esnaf ahlakını (fütüvvet) belirleyen bir kurumdu. Kalite kontrolü, fiyat narhı ve usta-çırak eğitimi yoluyla piyasayı düzenleyen Ahiler, aynı zamanda kriz anlarında sivil bir savunma ve dayanışma gücü olarak hareket etmişlerdir.\"</i><br><br><b>Ahilik teşkilatının Osmanlı kent hayatındaki rolü için hangisi söylenemez?</b>",
        secenekler: [
            "A) Ekonomik faaliyetleri ahlaki bir disiplin altına aldığı",
            "B) Zanaat eğitimini kurumsal bir sürekliliğe kavuşturduğu",
            "C) Tüketiciyi korumak amacıyla fiyat ve kalite denetimi yaptığı",
            "D) Toplumsal dayanışma ve yerel güvenlikte pay sahibi olduğu",
            "E) Devletin askeri ve mali işlerini tamamen kendi kontrolünde yürüttüğü"
        ],
        cevap: "E) Devletin askeri ve mali işlerini tamamen kendi kontrolünde yürüttüğü",
        aciklama: "Ahilik sivil ve ekonomik bir örgütlenmedir; devletin temel askeri ve mali yönetim fonksiyonlarını üstlenmesi söz konusu değildir."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u2_genel_2"] = [
    {
        soru: "<i>\"Osmanlı'nın kökeni meselesi, siyasi romantizmin tuzaklarından arındırılarak ele alındığında karşımıza çıkan tablo şudur: Osman Bey'in önderliğindeki topluluk, homojen bir Türkmen kabilesi değildi; aksine çok sayıda etnik ve sosyal kesimi bünyesinde barındıran, fırsatçı ve pragmatik bir koalisyondu. Bu esnek yapı, erken Osmanlı genişlemesinin hem gücü hem de özgünlüğüydü.\"</i><br><br><b>Lindner'ın bu analizine göre erken Osmanlı topluluğunun en belirleyici özelliği nedir?</b>",
        secenekler: [
            "A) Homojen bir Türkmen kimliğine dayanan güçlü etnik birlik",
            "B) Çok etnikli ve pragmatik koalisyon yapısının genişlemeyi olanaklı kılan esnekliği",
            "C) İslam'ı yaymaya adanmış katı ideolojik bir savaşçı topluluğu kimliği",
            "D) Selçuklu devlet geleneğini birebir devralan kurumsal muhafazakarlık",
            "E) Merkezi otoritenin aşiret liderleri üzerinde kurduğu tam baskı"
        ],
        cevap: "B) Çok etnikli ve pragmatik koalisyon yapısının genişlemeyi olanaklı kılan esnekliği",
        aciklama: "Lindner, Osmanlı'nın başlangıçta saf bir kabile yapısından ziyade, farklı kesimleri bir hedef etrafında toplayabilen pragmatik bir birliktelik (koalisyon) olduğunu savunur."
    },
    {
        soru: "<i>\"Osmanlı Devleti'nin kuruluşunda dervişlerin ve ahilerin oynadığı rol, salt bir dinî tebliğ meselesi değildir. Bu gruplar, fetholunan ıssız arazileri tarıma açarak, yolların güvenliğini sağlayarak ve kurdukları imaretlerle yerli halka sosyal hizmet sunarak devletin toprak tutma kapasitesini artırmışlardır. Bu sürece 'şenlendirme' adı verilir.\"</i><br><br><b>Barkan'ın 'şenlendirme' (kolonizasyon) kavramıyla vurguladığı temel durum hangisidir?</b>",
        secenekler: [
            "A) Bölge halkının zorla Müslümanlaştırılması",
            "B) Fethedilen toprakların ekonomik, sosyal ve kentsel altyapıyla yaşanabilir hale getirilmesi",
            "C) Askeri birliklerin sınırlarda kalıcı kışlalar inşa etmesi",
            "D) Yerel Hristiyan aristokrasinin tüm haklarının ellerinden alınması",
            "E) Eğitim sisteminin tamamen dini metinlere dayandırılması"
        ],
        cevap: "B) Fethedilen toprakların ekonomik, sosyal ve kentsel altyapıyla yaşanabilir hale getirilmesi",
        aciklama: "Barkan, dervişlerin ve zaviyelerin kurduğu düzenin, toprağı ekonomik ve sosyal bir çekim merkezine dönüştürerek kalıcı yerleşimi (vatanlaşmayı) sağladığını belirtir."
    },
    {
        soru: "<i>\"Sahn-ı Seman medreselerinin mimarisinde her bir dersliğin ve hücrenin eşit ölçülerde yan yana dizilmesi, bilginin ve alimlerin hakikat karşısındaki eşitliğini sembolize ediyordu. Bu mekan tasarımı, Fatih döneminin rasyonel ve disiplinli eğitim anlayışının fiziksel bir yansımasıdır.\"</i><br><br><b>Bu metne göre Sahn-ı Seman medreselerinin mimari yapısı hangi düşünceyi temsil eder?</b>",
        secenekler: [
            "A) Padişahın ulema üzerindeki mutlak baskısını",
            "B) Belirli bilim dallarının diğerlerinden daha üstün tutulduğunu",
            "C) Bilimsel faaliyetlerdeki düzeni ve bilginin demokratik/eşitlikçi ruhunu",
            "D) Medrese eğitiminin halktan tamamen izole edildiğini",
            "E) Mimari estetiğin eğitimin içeriğinden daha önemli sayıldığını"
        ],
        cevap: "C) Bilimsel faaliyetlerdeki düzeni ve bilginin demokratik/eşitlikçi ruhunu",
        aciklama: "Mimarideki simetri ve eşitlik, eğitim felsefesindeki 'hakikat arayışında eşitlik' ve 'akli disiplin' ilkelerinin mekana yansımış halidir."
    },
    {
        soru: "<i>\"Osmanlı'da 'padişahın adaletli olması' sadece ahlaki bir tavsiye değil, sistemin işleyişi için hukuki bir zorunluluktu. Tebaadan gelen bir şikâyet üzerine (arzuhal), padişahın kendi memuruna karşı köylünün hakkını koruması, devletin meşruiyetini halk nezdinde tazeleyen bir 'adalet dairesi' pratiğiydi.\"</i><br><br><b>Adalet dairesi kavramının Osmanlı yönetimindeki işlevi nedir?</b>",
        secenekler: [
            "A) Vergi yükünü sürekli artırarak orduyu güçlendirmek",
            "B) Hükümdar, ordu, hazine ve halk arasındaki karşılıklı bağımlılığı ve düzeni korumak",
            "C) Kanun koyma yetkisini tamamen yerel yöneticilere devretmek",
            "D) Yalnızca askeri sınıfın imtiyazlarını yasal güvenceye almak",
            "E) Padişahın tüm yetkilerini ulemanın onayına tabi kılmak"
        ],
        cevap: "B) Hükümdar, ordu, hazine ve halk arasındaki karşılıklı bağımlılığı ve düzeni korumak",
        aciklama: "Adalet dairesine göre; ordu için hazine, hazine için halk, halk için adalet, adalet için ise güçlü bir hükümdar gereklidir. Bu döngü istikrarın temelidir."
    },
    {
        soru: "<i>\"Bizans-Osmanlı sınırında faaliyet gösteren akıncı beyleri, zaman zaman Bizanslı 'tekfur'larla (yerel bey) kirve oluyor, ticaret yapıyor ve ortak düşmana karşı birleşebiliyorlardı. Bu 'sınır kültürü', dinsel ve siyasal karşıtlıkların gündelik yaşamda nasıl esneyebildiğini kanıtlar.\"</i><br><br><b>Lowry'nin vurguladığı bu 'sınır kültürü' Osmanlı'nın genişlemesine nasıl katkı sağlamıştır?</b>",
        secenekler: [
            "A) Bizans'ın tüm kurumlarının askeri güçle derhal yok edilmesine",
            "B) Yerel güçlerle kurulan pragmatik ilişkiler sayesinde fethin ön hazırlığının yapılmasına",
            "C) Müslüman olmayanların tamamının Anadolu'dan sürülmesine",
            "D) Osmanlı Devleti'nin Hristiyanlığı resmi din olarak kabul etmesine",
            "E) Aşiret bağlarının devlet kurumları karşısında tamamen zayıflamasına"
        ],
        cevap: "B) Yerel güçlerle kurulan pragmatik ilişkiler sayesinde fethin ön hazırlığının yapılmasına",
        aciklama: "Sınır boylarındaki esnek ilişkiler (pragmatizm), askeri harekatlardan önce bölgede siyasi ve sosyal bir zemin oluşturarak fethin kolaylaşmasını sağlamıştır."
    },
    {
        soru: "<i>\"Osmanlı askeri teşkilatındaki topçu ocağı, 15. yüzyılda Avrupa ordularıyla yarışabilecek bir teknolojiye sahipti. Ancak Osmanlı'nın başarısı sadece silah üretiminde değil, lojistik kapasitesindeydi. Dev topların yüzlerce kilometre öteye taşınması, yolların ve köprülerin bu ağır yüke göre organize edilmesi tam bir mühendislik başarısıydı.\"</i><br><br><b>Agoston'un bu analizine göre Osmanlı askeri gücünün gerçek sırrı nedir?</b>",
        secenekler: [
            "A) Sadece en gelişmiş silahlara sahip olmaları",
            "B) Silah teknolojisini mükemmel bir lojistik ve organizasyon kapasitesiyle birleştirmeleri",
            "C) Avrupa'dan getirilen yabancı uzmanların tüm orduyu yönetmesi",
            "D) Savaşlarda her zaman sayısal olarak iki kat üstün olmaları",
            "E) Barut üretimini gizli tutarak rakip devletlerin erişimini engellemeleri"
        ],
        cevap: "B) Silah teknolojisini mükemmel bir lojistik ve organizasyon kapasitesiyle birleştirmeleri",
        aciklama: "Metin, teknoloji kadar (top dökümü), o teknolojinin operasyonel hale getirilmesini sağlayan lojistik (taşıma, yol düzeni) başarısına vurgu yapar."
    },
    {
        soru: "<i>\"Osmanlı kadıları, verdikleri kararların kayıtlarını 'Şer'iye Sicilleri'ne titizlikle geçerlerdi. Bu defterlerde sadece mahkeme sonuçları değil; narh fiyatları, ferman suretleri ve halkın talepleri de yer alırdı. Bu durum, kadının taşrada sadece bir yargıç değil, aynı zamanda merkezin sesi ve halkın denetçisi olduğunu gösterir.\"</i><br><br><b>Kadıların görev alanı hakkında hangisi söylenebilir?</b>",
        secenekler: [
            "A) Sadece dini törenleri yönetmekle yükümlüdürler",
            "B) Adalet, idare, belediye ve denetim görevlerini tek bir makamda birleştirmişlerdir",
            "C) Valilerin emirlerini sorgusuz sualsiz yerine getiren memurlardır",
            "D) Sadece mülkiyet davalarına bakmak üzere uzmanlaşmışlardır",
            "E) Eğitim faaliyetlerinde hiçbir rolleri bulunmamaktadır"
        ],
        cevap: "B) Adalet, idare, belediye ve denetim görevlerini tek bir makamda birleştirmişlerdir",
        aciklama: "Metne göre kadı; hem hukuki karar verici, hem pazar fiyatlarını (narh) belirleyici, hem de merkezin emirlerini taşrada uygulayan idari bir figürdür."
    },
    {
        soru: "<i>\"1396 Niğbolu Savaşı'nda Haçlı koalisyonuna karşı kazanılan zafer, I. Bayezid'e İslam dünyasında 'Sultan-ı İklim-i Rum' (Anadolu'nun Sultanı) unvanını kazandırmıştır. Bu unvan, halife tarafından resmen tanınmak demekti ve Osmanlı'nın beylikten imparatorluğa geçişindeki ideolojik zirveyi simgeliyordu.\"</i><br><br><b>Niğbolu Zaferi'nin Osmanlı meşruiyeti açısından önemi nedir?</b>",
        secenekler: [
            "A) Anadolu birliğinin askeri zorlama olmaksızın kurulması",
            "B) Osmanlı hanedanının halife tarafından 'hükümdar' olarak resmen ve hukuken tescil edilmesi",
            "C) Bizans İmparatorluğu'nun bu tarihten itibaren vergiye bağlanması",
            "D) Haçlı Seferleri tehlikesinin Anadolu'da tamamen sona ermesi",
            "E) Osmanlı başkentinin Bursa'dan İstanbul'a taşınması"
        ],
        cevap: "B) Osmanlı hanedanının halife tarafından 'hükümdar' olarak resmen ve hukuken tescil edilmesi",
        aciklama: "Kazanılan askeri başarı, dini liderlik olan Halifelik makamı tarafından tanınarak Osmanlı Devleti'ne uluslararası İslam dünyasında yüksek bir yasal meşruiyet ve prestij kazandırmıştır."
    },
    {
        soru: "<i>\"Erken Osmanlı döneminde 'abdalan-ı Rum' veya 'bacıyan-ı Rum' gibi grupların varlığı, toplumsal yapının tek tip olmadığını; kadınların ve gezgin dervişlerin de fetihten yerleşime kadar her aşamada aktif sorumluluk aldığını gösterir. Bu heterojen sosyal dinamizm, Osmanlı'nın hızlı büyümesini sağlayan enerjinin kaynağıdır.\"</i><br><br><b>Ocak'ın bu tespiti Osmanlı toplum yapısı hakkında hangisini kanıtlar?</b>",
        secenekler: [
            "A) Toplumun yalnızca elit ve soylu sınıflar tarafından yönetildiğini",
            "B) Farklı sosyal ve mesleki grupların devlet inşasında aktif ve katılımcı bir rol oynadığını",
            "C) Kadınların sadece hane içinde kalarak toplumsal hayattan dışlandığını",
            "D) Dervişlerin sadece askeri seferlerde görev aldığını",
            "E) Toplumda sınıflar arası geçişin imkânsız olduğunu"
        ],
        cevap: "B) Farklı sosyal ve mesleki grupların devlet inşasında aktif ve katılımcı bir rol oynadığını",
        aciklama: "Farklı grupların (dervişler, kadın teşkilatları vb.) sürece dahil olması, kuruluşun geniş tabanlı bir toplumsal hareket niteliğinde olduğunu kanıtlar."
    },
    {
        soru: "<i>\"Osmanlı tıp eğitiminin verildiği darüşşifalar, birer usta-çırak okulu gibi çalışırdı. Başhekimler (Sertabib), öğrencileri bizzat hasta başında eğitir; tıp bilgisi kağıttan değil, uygulamadan öğrenilirdi. Bu 'klinik eğitim' modeli, 15. yüzyıl tıbbının başarısının temelidir.\"</i><br><br><b>Metne göre Osmanlı tıp eğitiminin temel özelliği nedir?</b>",
        secenekler: [
            "A) Sadece eski Yunan ve Hint kitaplarının ezberletilmesi",
            "B) Teorik bilgi ile pratik uygulamanın (hasta başı eğitimi) birleştirilmesi",
            "C) Hekimlerin sadece sarayda yetiştirilmesi",
            "D) Cerrahi müdahalelerin tamamen yasaklanmış olması",
            "E) Tıp eğitiminin sadece din adamları tarafından verilmesi"
        ],
        cevap: "B) Teorik bilgi ile pratik uygulamanın (hasta başı eğitimi) birleştirilmesi",
        aciklama: "Uygulamalı (klinik) eğitim vurgusu, tıbbın sadece kitabi bir alan değil, bizzat hasta üzerinde deneyimlenerek öğrenilen bir disiplin olduğunu gösterir."
    },
    {
        soru: "<i>\"Osmanlı askeri gücünün lojistik başarısında 'derbentçiler' kritik rol oynardı. Stratejik geçitleri ve dağ yollarını koruyan bu yerel görevliler, ordunun sevkıyat güvenliğini sağlar ve ticaret kervanlarını korurlardı. Karşılığında ise bazı vergilerden muaf tutulurlardı.\"</i><br><br><b>Derbent teşkilatının Osmanlı idaresindeki birincil işlevi hangisidir?</b>",
        secenekler: [
            "A) Sınırların dışına akınlar düzenlemek",
            "B) Ulaşım hatlarının güvenliğini sağlayarak ordu ve ticaret akışını korumak",
            "C) Müslüman olmayan tebaayı yerinden etmek",
            "D) Sadece başkentin asayişini sağlamak",
            "E) Devletin resmi tarih kayıtlarını tutmak"
        ],
        cevap: "B) Ulaşım hatlarının güvenliğini sağlayarak ordu ve ticaret akışını korumak",
        aciklama: "Derbentçiler, ulaşım yolları üzerindeki düğüm noktalarını tutarak hem askeri lojistiği hem de ekonomik canlılığı (kervan güvenliği) tesis etmişlerdir."
    },
    {
        soru: "<i>\"Osmanlı mimari geleneğinde külliye, şehrin sosyal dokusunu örgütleyen bir merkezdir. Caminin etrafındaki medrese, kütüphane, imaret ve darüşşifa, toplumun tüm temel ihtiyaçlarını aynı mekânda karşılar. Bu bütüncül yapı, İslam medeniyetindeki 'hayatın merkezinde ibadet ve hizmet' anlayışını temsil eder.\"</i><br><br><b>Külliye yapısının kentsel yaşamdaki rolü hangisidir?</b>",
        secenekler: [
            "A) Toplumu birbirinden izole mahalleler halinde ayırmak",
            "B) Eğitim, sağlık ve sosyal hizmetleri dini mekanla bütünleştirerek kentsel bir odak noktası yaratmak",
            "C) Yalnızca askeri savunma amacıyla yüksek surlar inşa etmek",
            "D) Ticari faaliyetleri tamamen kentsel yaşamın dışına taşımak",
            "E) Sadece hanedan üyeleri için lüks yaşam alanları oluşturmak"
        ],
        cevap: "B) Eğitim, sağlık ve sosyal hizmetleri dini mekanla bütünleştirerek kentsel bir odak noktası yaratmak",
        aciklama: "Külliye, bir kentin kalbi olarak işlev görür ve dini hayat ile sivil hizmetleri (eğitim, aşevi, hastane) bir arada sunan bir ekosistem oluşturur."
    },
    {
        soru: "<i>\"Osmanlı'nın fethettiği yerlerdeki yerel kanunlara (Sırp, Bulgar, Bizans yasaları) saygı duyması ve bunları 'Adet-i Kadime' adıyla sisteme entegre etmesi, fethin sarsıcı etkisini azaltmıştır. Halk, tanıdığı kurallar altında yaşamaya devam ederken sadece en tepedeki otorite değişmiş oluyordu.\"</i><br><br><b>Bu durumun istimalet politikasıyla ilişkisi nedir?</b>",
        secenekler: [
            "A) Tüm yerel yasaların derhal lağvedilmesi",
            "B) Halkın alışkın olduğu hukuk düzenini koruyarak adaptasyonu kolaylaştırmak ve huzuru sağlamak",
            "C) Osmanlı yasalarının yetersiz kaldığını kabul etmek",
            "D) Yerel halkın kendi ordusunu kurmasına izin vermek",
            "E) Sadece gayrimüslimleri yönetime ortak etmek"
        ],
        cevap: "B) Halkın alışkın olduğu hukuk düzenini koruyarak adaptasyonu kolaylaştırmak ve huzuru sağlamak",
        aciklama: "Var olan hukuki alışkanlıkların sürdürülmesi (pragmatizm), yerel halkın yeni idareye direnişini azaltan ve istikrarı sağlayan akıllıca bir yöntemdir."
    },
    {
        soru: "<i>\"Ali Kuşçu'nun getirdiği Semerkand matematik ekolü, medreselerdeki 'astronomi tabloları' (zîc) çalışmalarını canlandırdı. Bu çalışmalar sadece gökyüzünü anlamak için değil; kıblenin tayini, namaz vakitlerinin belirlenmesi ve denizcilikte rota tayini gibi pratik ihtiyaçlar için yapılıyordu.\"</i><br><br><b>Ali Kuşçu'nun getirdiği bilimsel birikimin toplumsal hayattaki pratik faydası hangisidir?</b>",
        secenekler: [
            "A) Şehirlerin sadece savunma duvarlarını güçlendirmek",
            "B) Dini ibadetlerin ve ticari denizciliğin zaman ve yön tayini gibi ihtiyaçlarını bilimsel olarak çözmek",
            "C) Avrupa dillerinden tercüme hareketini başlatmak",
            "D) Tarım arazilerini sadece askeri amaçlı kullanmak",
            "E) Tımar sistemindeki vergi yolsuzluklarını önlemek"
        ],
        cevap: "B) Dini ibadetlerin ve ticari denizciliğin zaman ve yön tayini gibi ihtiyaçlarını bilimsel olarak çözmek",
        aciklama: "Metin, astronomi ve matematik çalışmalarının hem dini pratiklerdeki (kıble, vakit) hem de denizcilikteki somut kullanım alanlarına işaret eder."
    },
    {
        soru: "<i>\"Osmanlı tahrir defterlerinde yapılan düzenli sayımlar, devletin tebaasıyla olan 'hukuki sözleşmesi'dir. Kimin ne ekeceği, ne kadar vergi vereceği ve hangi muafiyetlere sahip olduğu bu defterlerde yazar. Bu yazılı kayıt, memurların halka keyfi davranmasını engelleyen en büyük engeldir.\"</i><br><br><b>Tahrir kayıtlarının halk nezdindeki güvence değeri nedir?</b>",
        secenekler: [
            "A) Halkın vergi ödemekten tamamen kurtulması",
            "B) Hak ve sorumlulukların yazılı tesciliyle keyfi yönetime karşı yasal güvence oluşturması",
            "C) Sadece askeri sayıların belirlenmesi",
            "D) Anadolu'daki nüfusun Balkanlara göçünün yasaklanması",
            "E) Kitap üretiminin devlet kontrolüne girmesi"
        ],
        cevap: "B) Hak ve sorumlulukların yazılı tesciliyle keyfi yönetime karşı yasal güvence oluşturması",
        aciklama: "Yazılı bürokrasi, kural ve sorumlulukları sabitleyerek tebaayı yerel yöneticilerin keyfi baskı ve haksız vergi taleplerinden koruyan bir 'hukuk devleti' aracıdır."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u2_genel_3"] = [
    {
        soru: "<i>\"Osmanlı tarihçiliğinde 'Gazi Tezi' (Wittek) ve 'Kurumsal Süreklilik Tezi' (Köprülü) uzun süre rekabet etmiştir. Ancak modern araştırmalar, kuruluşun tek bir 'anahtar' kelimeyle açıklanamayacağını; hem gaza ruhunun hem de Selçuklu-Bizans miraslarının etkileşiminin esas olduğunu göstermiştir.\"</i><br><br><b>Bu metne göre Osmanlı kuruluşunu anlamak için en tutarlı bilimsel yaklaşım hangisidir?</b>",
        secenekler: [
            "A) Sadece askeri zaferlere odaklanan bir anlatı benimsemek",
            "B) Tek bir faktörü değil, ideolojik, kurumsal ve coğrafi etkenlerin sentezini dikkate alan çok boyutlu bir analiz yapmak",
            "C) Kurumsal mirası reddederek sadece aşiret dinamiklerini incelemek",
            "D) Gaza ideolojisinin hiçbir etkisinin olmadığını savunmak",
            "E) Osmanlı tarihini yalnızca Bizans kaynaklarına dayanarak yeniden yazmak"
        ],
        cevap: "B) Tek bir faktörü değil, ideolojik, kurumsal ve coğrafi etkenlerin sentezini dikkate alan çok boyutlu bir analiz yapmak",
        aciklama: "Metin, kuruluşun tek bir nedene indirgenemeyeceğini, rakip gibi görünen tezlerin birleşiminden (sentezinden) daha doğru bir tablo çıkacağını savunur."
    },
    {
        soru: "<i>\"13. yüzyılda Moğol baskısı Anadolu'daki Selçuklu düzenini yıkarken, paradoks biçimde uç bölgelerinde Osmanlı gibi dinamik bir gücün filizlenmesine yol açmıştır. Moğollardan kaçan ulema, derviş ve askerlerin bu bölgelere yığılması, Osmanlı'ya hazır bir devlet kapasitesi sağlamıştır.\"</i><br><br><b>İnalcık'ın bu tespiti Osmanlı'nın kuruluşunu hangi faktörle ilişkilendirir?</b>",
        secenekler: [
            "A) Tamamen tesadüfi bir şans faktörüyle",
            "B) Dış baskının (Moğol) yarattığı demografik ve entelektüel göç dalgasının sağladığı insan kaynağıyla",
            "C) Bizans'ın Osmanlı'ya olan doğrudan mali yardımlarıyla",
            "D) Türkmenlerin askeri disiplinden tamamen vazgeçmesiyle",
            "E) Sadece iklimsel ve coğrafi değişikliklerin etkisiyle"
        ],
        cevap: "B) Dış baskının (Moğol) yarattığı demografik ve entelektüel göç dalgasının sağladığı insan kaynağıyla",
        aciklama: "Moğol istilasının Anadolu'nun batısında (uçlarda) yoğun bir nitelikli nüfus (alimler, askerler) birikimine yol açması, Osmanlı'nın hızlı devletleşme sürecini besleyen beşeri altyapıyı kurmuştur."
    },
    {
        soru: "<i>\"Osmanlı vergi sistemindeki 'haraç' ve 'cizye', gayrimüslim tebaanın can ve mal güvenliğinin, dini özgürlüklerinin devlete olan mali karşılığıdır. İstimalet çerçevesinde bu vergilerin sabitlenmesi ve keyfi artırılmaması, Balkanlardaki yerel halkı Osmanlı yönetimine bağlamıştır.\"</i><br><br><b>Bu bilgiye göre, vergilerin 'istimalet' (hoşgörü) politikasındaki yeri nedir?</b>",
        secenekler: [
            "A) Gayrimüslimleri ekonomik olarak zayıflatmak için kullanılması",
            "B) Adaletli vergilendirme yoluyla halkın güvenini ve devlete olan rızasını kazanmak",
            "C) Vergi gelirlerini tamamen askeri harcamalardan çıkarmak",
            "D) Müslüman tebaadan daha ağır vergiler alarak adaleti sağlamak",
            "E) Ticareti sadece devlete bağlı kılmak"
        ],
        cevap: "B) Adaletli vergilendirme yoluyla halkın güvenini ve devlete olan rızasını kazanmak",
        aciklama: "Hukuki ve adil vergi uygulaması, fethedilen halk için Osmanlı idaresini eski yöneticilerine göre daha cazip ve güvenilir bir otorite haline getirmiştir."
    },
    {
        soru: "<i>\"Sahn-ı Seman medreselerinin kurucusu Fatih Sultan Mehmet, Ali Kuşçu'ya günlük 200 akçe maaş bağlamış ve onu matematik-astronomi dersleri vermesi için görevlendirmiştir. Bu durum, Osmanlı'da bilim insanına verilen değerin ve akli ilimlerin devlet hiyerarşisindeki öneminin kanıtıdır.\"</i><br><br><b>Padişahın bir bilim insanına yüksek maaş bağlaması neyi temsil eder?</b>",
        secenekler: [
            "A) Devlet hazinesinin gereksiz israf edildiğini",
            "B) Bilimsel üretimin teşvik edildiğini ve ilmiye sınıfının itibarının korunduğunu",
            "C) Sadece yabancı alimlerin ödüllendirildiğini",
            "D) Medrese eğitiminin tamamen ücretli hale getirildiğini",
            "E) Bilimin askeri güçten daha önemsiz sayıldığını"
        ],
        cevap: "B) Bilimsel üretimin teşvik edildiğini ve ilmiye sınıfının itibarının korunduğunu",
        aciklama: "Yüksek maaş ve teşvikler, devletin bilimsel birikimi stratejik bir değer olarak gördüğünü ve liyakatli alimleri merkeze çekmek istediğini gösterir."
    },
    {
        soru: "<i>\"Osmanlı fetihlerinden sonra kurulan 'mahalle' yapısı, dinler arası diyaloğun mekansal yansımasıdır. Aynı sokakta cami, kilise ve havranın yan yana bulunması, istimalet politikasının kağıt üzerinde değil sokakta yaşadığını kanıtlar.\"</i><br><br><b>Metne göre Osmanlı şehircilik anlayışının temel özelliği nedir?</b>",
        secenekler: [
            "A) Her dini grubun tamamen ayrı şehirlerde yaşaması",
            "B) Dini ve kültürel çeşitliliğin bir arada, hoşgörü içinde varlığını sürdürdüğü çoğulcu yapı",
            "C) Tüm mabetlerin tek bir dinin kontrolüne girmesi",
            "D) Şehirlerin sadece askeri savunma için tasarlanması",
            "E) Yerel halkın şehir merkezlerine girmesinin yasaklanması"
        ],
        cevap: "B) Dini ve kültürel çeşitliliğin bir arada, hoşgörü içinde varlığını sürdürdüğü çoğulcu yapı",
        aciklama: "Farklı inanç mekanlarının bir arada bulunması, Osmanlı idaresinin toplumsal çeşitliliği barış içinde yönetme (istimalet) becerisini somutlaştırır."
    },
    {
        soru: "<i>\"Osmanlı askeri yapısında tımarlı sipahiler yerli Türkmenlerden oluşurken, Yeniçeriler devşirme kökenlilerden oluşurdu. Devlet, bu iki grubu birbirine rakip olarak dengelemiş; böylece bir grubun aşırı güçlenip merkeze isyan etmesini engellemiştir.\"</i><br><br><b>Metinde anlatılan 'dengeleme' stratejisinin amacı nedir?</b>",
        secenekler: [
            "A) Orduyu zayıflatarak savaşları durdurmak",
            "B) Merkezi otoriteyi ve sultanın mutlak gücünü iç tehditlere karşı korumak",
            "C) Türkmenlerin yönetimden tamamen dışlanmasını sağlamak",
            "D) Yeniçeri sayısını sürekli azaltmak",
            "E) Etnik çatışmaları körükleyerek devleti yönetmek"
        ],
        cevap: "B) Merkezi otoriteyi ve sultanın mutlak gücünü iç tehditlere karşı korumak",
        aciklama: "Farklı toplumsal kökenlerden gelen askeri güçlerin (kul sistemi vs. tımarlı sipahi) birbirini dengelemesi, merkezi yapının herhangi bir yerel güce bağımlı kalmamasını sağlar."
    },
    {
        soru: "<i>\"İrfan geleneğinde alimin ve dervişin 'dünya malına tamah etmemesi' öğütlenirdi. Ancak bu, fakirlik övgüsü değil; servetin bir güç göstergesi olarak değil, topluma hizmet amacıyla vakıf yoluyla paylaşılması demekti. Osmanlı'daki devasa vakıf ağı bu irfanın sonucudur.\"</i><br><br><b>Metne göre Osmanlı vakıf sisteminin ahlaki temeli hangisidir?</b>",
        secenekler: [
            "A) Sadece zenginliği gizlemek",
            "B) Kişisel birikimin toplumsal faydaya ve hizmete dönüştürülmesi ilkesi",
            "C) Devletin tüm vergileri toplamasına engel olmak",
            "D) Sadece dini yapıların masraflarını karşılamak",
            "E) Kapitalist bir ekonomik düzen kurmak"
        ],
        cevap: "B) Kişisel birikimin toplumsal faydaya ve hizmete dönüştürülmesi ilkesi",
        aciklama: "İrfan anlayışı, bireysel sermayenin 'vakıf' yoluyla kamusal hizmete (eğitim, aşevi, hastane) dönüştürülmesini toplumsal bir sorumluluk olarak kurgular."
    },
    {
        soru: "<i>\"Millet sistemi çerçevesinde Rum, Ermeni ve Yahudi cemaatlerine kendi okullarını kurma ve kendi dillerinde eğitim verme hakkı tanınmıştır. Bu özgürlük, tebaanın kültürel kimliğini korumasını sağlarken devlete karşı isyan etme motivasyonunu da azaltmıştır.\"</i><br><br><b>Eğitimdeki bu özerkliğin siyasi etkisi nedir?</b>",
        secenekler: [
            "A) Milliyetçilik akımlarını anında başlatması",
            "B) Toplumsal rızayı artırarak İmparatorluk içindeki barışı ve istikrarı sağlaması",
            "C) Türkçe dilinin tamamen unutulması",
            "D) Müslümanların eğitim almasını engellemesi",
            "E) Tüm dillerin yasaklanması"
        ],
        cevap: "B) Toplumsal rızayı artırarak İmparatorluk içindeki barışı ve istikrarı sağlaması",
        aciklama: "Kültürel kimliğe duyulan saygı ve tanınan haklar, tebaanın kendisini devletin baskı altında hissetmemesini sağlayarak siyasi sadakati güçlendirir."
    },
    {
        soru: "<i>\"Osmanlı medreselerindeki 'şerh' ve 'haşiye' yazımı geleneği, eski bilginin modern ihtiyaçlara göre yeniden yorumlanmasıdır. Bu yöntem sayesinde İslam medeniyetinin klasikleri ile Osmanlı dünyasının güncel sorunları arasında bir köprü kurulmuştur.\"</i><br><br><b>Şerh geleneğinin Osmanlı ilmine katkısı nedir?</b>",
        secenekler: [
            "A) Eski bilgileri olduğu gibi kopyalayarak yeniliğe kapatmak",
            "B) Geçmişin bilgi birikimini bugünün şartlarıyla güncelleyerek sürekliliği sağlamak",
            "C) Sadece çeviri yaparak özgün üretimi durdurmak",
            "D) Felsefeyi tamamen eğitim dışına itmek",
            "E) Sadece dini metinleri sadeleştirmek"
        ],
        cevap: "B) Geçmişin bilgi birikimini bugünün şartlarıyla güncelleyerek sürekliliği sağlamak",
        aciklama: "Şerh; metni sadece açıklamak değil, ona yeni yorumlar ve çözümler ekleyerek bilginin 'yaşayan' bir formda kalmasını sağlamaktır."
    },
    {
        soru: "<i>\"Bursa'da fetihten sonra kurulan 'Boya-hane', 'Dokuma-hane' gibi zanaat binaları, şehrin sadece askeri değil sanayi birikimi üzerinde de yükseldiğini gösterir. Osmanlı, yerel zanaatkarların tecrübesinden faydalanarak kendi üretim standartlarını belirlemiştir.\"</i><br><br><b>Osmanlı şehirciliğindeki bu uygulama neyi ifade eder?</b>",
        secenekler: [
            "A) Yerel zanaatkarların hepsinin bölgeden sürülmesini",
            "B) Mevcut ekonomik tecrübenin devralınarak kurumsallaştırılmasını ve geliştirilmesini",
            "C) Sadece Türklerin ticaret yapmasına izin verilmesini",
            "D) Şehirlerin sadece tarım merkezi olarak kalmasını",
            "E) Bizans ekonomisinin tamamen iflas ettirilmesini"
        ],
        cevap: "B) Mevcut ekonomik tecrübenin devralınarak kurumsallaştırılmasını ve geliştirilmesini",
        aciklama: "Osmanlı fethettiği kentlerdeki ticari ve sınai altyapıyı korumuş, mevcut uzmanlığı kendi kurumsal yapılarına (lonca vb.) dahil ederek üretimi büyütmüştür."
    },
    {
        soru: "<i>\"Osmanlı askeri lojistiğinde 'menzil' teşkilatı hayatiydi. Sefer yolları üzerindeki bu istasyonlar, ordunun yiyecek, su ve binek hayvanı ihtiyacını önceden hazırlar; istihbarat akışını hızlandırırdı. Menzil sistemi olmasaydı devasa orduların disiplini korunamazdı.\"</i><br><br><b>Menzil sisteminin askeri harekatlardaki rolü nedir?</b>",
        secenekler: [
            "A) Düşmanla doğrudan savaşan öncü birlikler olmak",
            "B) Ordunun lojistik ve iaşe ihtiyaçlarını koordine ederek harekat kabiliyetini artırmak",
            "C) Sadece padişahın çadırını taşımak",
            "D) Savaş ganimetlerini toplamak",
            "E) Balkanlardan Anadolu'ya göçleri organize etmek"
        ],
        cevap: "B) Ordunun lojistik ve iaşe ihtiyaçlarını koordine ederek harekat kabiliyetini artırmak",
        aciklama: "Lojistik destek noktaları olan menziller, ordunun hızlı ve disiplinli bir şekilde uzun mesafeleri aşmasını sağlayan stratejik bir ağdır."
    },
    {
        soru: "<i>\"Osmanlı vakıfnamelerinde yer alan 'hayvanların kışın beslenmesi' veya 'göçmen kuşların korunması' gibi şartlar, irfan geleneğinin varlığa duyduğu saygının hukuki belgeleridir. Bu duyarlılık, şehircilikten günlük yaşama kadar her alanı merhamet ekseninde şekillendirmiştir.\"</i><br><br><b>Bu durum Osmanlı medeniyet tasavvuru hakkında ne söyler?</b>",
        secenekler: [
            "A) Doğanın tamamen insan kontrolünde bir kaynak olarak görüldüğünü",
            "B) Merhamet ve sorumluluk bilincinin tüm canlıları kapsayan geniş bir ahlak nizamı oluşturduğunu",
            "C) Vakıfların sadece insanlar için kurulması gerektiğini",
            "D) Hayvan haklarının yasalardan daha önemli sayıldığını",
            "E) Doğal kaynakların ekonomik olarak sömürüldüğünü"
        ],
        cevap: "B) Merhamet ve sorumluluk bilincinin tüm canlıları kapsayan geniş bir ahlak nizamı oluşturduğunu",
        aciklama: "Hayvanları ve doğayı korumaya yönelik vakıf şartları, Osmanlı'daki irfanın 'tüm yaratılmışlara şefkat' ilkesinin kurumsal yansımasıdır."
    },
    {
        soru: "<i>\"Osmanlı hukukunda 'tahrir' çalışmaları, toprağın kime ait olduğunu değil, verginin kime verileceğini tespit ederdi. Çünkü toprak mülkiyeti her zaman devletindi (Miri). Bu sistem, toprak üzerinden büyük hanedanların veya toprak ağalarının doğmasını engellemiştir.\"</i><br><br><b>Miri toprak rejiminin temel siyasi işlevi nedir?</b>",
        secenekler: [
            "A) Toprağı parçalara ayırarak halka hediye etmek",
            "B) Merkezi otoriteye rakip olabilecek yerel güç odaklarının (aristokrasi) oluşmasını önlemek",
            "C) Sadece tarımla uğraşanları cezalandırmak",
            "D) Vergi sistemini tamamen kaldırmak",
            "E) Toprak mülkiyetini ulemaya devretmek"
        ],
        cevap: "B) Merkezi otoriteye rakip olabilecek yerel güç odaklarının (aristokrasi) oluşmasını önlemek",
        aciklama: "Toprak mülkiyetinin devlette kalması, yerel idarecilerin ve soylu ailelerin toprak zenginliği üzerinden siyasi otorite devşirmesini ve padişaha rakip olmasını engeller."
    },
    {
        soru: "<i>\"Osmanlı medreselerindeki 'muid'ler, müderrisin dersini tekrar eden yardımcı hocalardı. Bu sistem sadece dersin anlaşılmasını sağlamaz; aynı zamanda öğrencinin hoca olma yolundaki pedagojik gelişimini de denetlerdi. Osmanlı eğitimi tecrübe aktarımına dayanıyordu.\"</i><br><br><b>Muidlik sisteminin eğitim kalitesine katkısı nedir?</b>",
        secenekler: [
            "A) Derslerin süresini kısaltmak",
            "B) Bilginin derinlemesine pekiştirilmesini ve yeni nesil alimlerin yetişme sürecini denetlemeyi sağlamak",
            "C) Müderrislerin görevini tamamen ellerinden almak",
            "D) Öğrenci sayısını azaltmak",
            "E) Sadece sözlü sınav yapmak"
        ],
        cevap: "B) Bilginin derinlemesine pekiştirilmesini ve yeni nesil alimlerin yetişme sürecini denetlemeyi sağlamak",
        aciklama: "Muidlik, eğitimin hem verimliliğini artırır hem de alim adaylarının öğretmenlik becerilerini usta-çırak disiplini içinde geliştirmelerini sağlar."
    },
    {
        soru: "<i>\"Osmanlı İmparatorluğu'nun kuruluşundan İstanbul'un fethine kadar geçen süreçte ilim ve irfan geleneği, devleti 'küçük bir sınır beyliği'nden 'cihanşümul bir imparatorluk' zihniyetine taşımıştır. Bu zihniyetin temel harcı, adaletin ve bilginin her şeyden üstün tutulmasıdır.\"</i><br><br><b>Bu metnin ana düşüncesi aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Osmanlı'nın sadece askeri fetihlerle büyüdüğü",
            "B) İlim ve irfan birikiminin, siyasi ve askeri yapıyı cihanşümul bir vizyona ve medeniyete dönüştürdüğü",
            "C) İstanbul'un fethinden sonra bilimin önemini kaybettiği",
            "D) Beylik döneminin kurumsal açıdan daha üstün olduğu",
            "E) Adalet kavramının sadece fetihler için bir araç olduğu"
        ],
        cevap: "B) İlim ve irfan birikiminin, siyasi ve askeri yapıyı cihanşümul bir vizyona ve medeniyete dönüştürdüğü",
        aciklama: "Askeri başarıların kalıcı bir imparatorluk ve medeniyete evrilmesi, adaleti ve bilgiyi merkeze alan düşünsel bir altyapıyla (ilim-irfan) mümkün olmuştur."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u2_genel_4"] = [
    {
        soru: "<i>\"Bapheus Savaşı sonrasında Osmanlı kuvvetlerinin İzmit'i ve çevre kaleleri abluka altına alması, Bizans'ın Anadolu ile olan son kara bağlantılarını zayıflatmıştır. Bu, Bizans için ekonomik bir darbe olduğu kadar, moral açıdan da bir çöküştü.\"</i><br><br><b>Metne göre Osmanlı'nın kuşatma stratejisinin Bizans üzerindeki etkisi nedir?</b>",
        secenekler: [
            "A) Bizans'ın derhal barış antlaşması imzalamasını sağlamıştır.",
            "B) Bizans'ı hem ekonomik hem de psikolojik olarak yalnızlaştırarak savunma direncini kırmıştır.",
            "C) Bizans'ın Avrupa'dan büyük bir ordu çağırmasına neden olmuştur.",
            "D) Sadece kale duvarlarının fiziksel olarak yıkılmasını sağlamıştır.",
            "E) Bizans halkının Anadolu'ya göç etmesini başlatmıştır."
        ],
        cevap: "B) Bizans'ı hem ekonomik hem de psikolojik olarak yalnızlaştırarak savunma direncini kırmıştır.",
        aciklama: "Abluka ve kara bağlantısının kesilmesi, Bizans'ın kaynaklarını ve direnme iradesini yıpratan stratejik bir yıpratma savaşıdır."
    },
    {
        soru: "<i>\"İstimalet politikasının en belirgin yansıması 'adaletname'lerdir. Padişahın, yerel idarecilerin halka aşırı vergi yüklemesini veya kötü davranmasını yasaklayan bu emirleri, Osmanlı yönetiminin tebaayı koruyan adil karakterini pekiştirmiştir.\"</i><br><br><b>Adaletnamelerin Osmanlı devlet yönetimindeki işlevi nedir?</b>",
        secenekler: [
            "A) Merkezi otoritenin taşra memurları üzerindeki denetimini ve adaleti sağlamak",
            "B) Sadece askeri kuralları belirlemek",
            "C) Yerel yöneticilere daha fazla yetki vermek",
            "D) Gayrimüslimlerin askere alınmasını zorunlu kılmak",
            "E) Vergi gelirlerini ulema sınıfına devretmek"
        ],
        cevap: "A) Merkezi otoritenin taşra memurları üzerindeki denetimini ve adaleti sağlamak",
        aciklama: "Adaletnameler, halkın idareciler tarafından ezilmesini önleyerek adalet dairesinin işlemesini ve devletin meşruiyetini korur."
    },
    {
        soru: "<i>\"Osmanlı askeri tarihindeki 'Pençik' uygulaması, savaş esirlerinin beşte birinin padişah için ayrılıp asker yetiştirilmesidir. Bu yöntem, ordunun insan kaynağı ihtiyacını karşılamada önemli bir basamak olmuştur; ancak fetihler yavaşladığında yetersiz kalmıştır.\"</i><br><br><b>Pençik uygulamasının temel sınırlılığı nedir?</b>",
        secenekler: [
            "A) Esirlerin Müslüman olmayı reddetmesi",
            "B) Savaşlara ve esir sayısına bağımlı bir sistem olması",
            "C) Askerlerin maaşlarının çok yüksek olması",
            "D) Sistemin sadece deniz savaşlarında uygulanması",
            "E) Esirlerin kaçma riskinin çok yüksek olması"
        ],
        cevap: "B) Savaşlara ve esir sayısına bağımlı bir sistem olması",
        aciklama: "Pençik, kaynağı dışa (savaşa) bağlı bir sistemdir. Savaşlar durduğunda veya yavaşladığında asker ihtiyacını karşılayamaz hale geldiği için yerini devşirmeye bırakmıştır."
    },
    {
        soru: "<i>\"Vakıf toprakları 'temlik' (mülk verme) yoluyla değil, kişilerin mülklerini kamu yararına bağışlamasıyla oluşurdu. Bu topraklar vergi dışı tutulurdu. Bu sayede eğitim ve hayır hizmetleri hazineye yük olmadan asırlarca sürmüştür.\"</i><br><br><b>Vakıf sisteminin mali açıdan devlete sağladığı kolaylık nedir?</b>",
        secenekler: [
            "A) Devletin tüm binaları kendi bütçesiyle yapmasını sağlaması",
            "B) Sosyal ve kültürel hizmetlerin maliyetini sivil bağışlar yoluyla bütçe dışından karşılaması",
            "C) Padişahın hazinesini sadece savaşlar için saklaması",
            "D) Ticaret yollarını vergiden muaf tutması",
            "E) Tüm dervişlerin maaşlarını orduya bağlaması"
        ],
        cevap: "B) Sosyal ve kültürel hizmetlerin maliyetini sivil bağışlar yoluyla bütçe dışından karşılaması",
        aciklama: "Vakıf sistemi, sosyal devlet işlevlerinin finansmanını devlete değil, hayırsever bireylerin mülk gelirlerine yükleyen rasyonel bir modeldir."
    },
    {
        soru: "<i>\"İskân politikasında dervişlerin ıssız yerlerde kurduğu zaviyeler, çevre bölgelerdeki yerel halkla Osmanlı idaresi arasında 'kültürel bir ara yüz' oluşturmuştur. Dervişlerin yardımseverliği, İslam'ın ve Osmanlı'nın imajını olumlu etkilemiştir.\"</i><br><br><b>Bu metne göre dervişlerin iskândaki asıl başarısı nedir?</b>",
        secenekler: [
            "A) Büyük ordular kurup savaşmaları",
            "B) Sosyal hizmet ve ahlaki temsil yoluyla halkın gönlünü kazanıp meşruiyet sağlamaları",
            "C) Yerel dilleri yasaklamaları",
            "D) Sadece kendi iç dünyalarına çekilmeleri",
            "E) Vergi memuru olarak görev yapmaları"
        ],
        cevap: "B) Sosyal hizmet ve ahlaki temsil yoluyla halkın gönlünü kazanıp meşruiyet sağlamaları",
        aciklama: "Dervişler, sundukları karşılıksız hizmet ve sergiledikleri derviş ahlakı ile yerel halkla duygusal bir bağ kurarak fethin toplumsal kabulünü sağlamışlardır."
    },
    {
        soru: "<i>\"Osmanlı hukukunda bir kadının evlilikten doğan haklarını koruması veya bir gayrimüslimin haksız vergiye itiraz etmesi kadı sicillerinde belgelenmiştir. Bu kayıtlar, adaletin her toplumsal kesime ulaştırıldığının kanıtıdır.\"</i><br><br><b>Kadı sicillerinin (şer'iye sicilleri) tarih araştırması açısından en özgün değeri nedir?</b>",
        secenekler: [
            "A) Sadece askeri zaferlerin tarihlerini vermesi",
            "B) Sıradan insanların hak arama süreçlerini ve gündelik yaşamdaki adalet uygulamalarını yansıtması",
            "C) Padişahın özel emirlerini içermesi",
            "D) Yalnızca zengin tüccarların ticari ilişkilerini kaydetmesi",
            "E) Toplumun tümünün Müslüman olduğunu kanıtlaması"
        ],
        cevap: "B) Sıradan insanların hak arama süreçlerini ve gündelik yaşamdaki adalet uygulamalarını yansıtması",
        aciklama: "Mahkeme kayıtları (siciller), toplumun her tabakasının adalete erişimini ve gündelik yaşam problemlerini gösteren en temel sosyal tarih kaynağıdır."
    },
    {
        soru: "<i>\"Müntahabat-ı Şifa gibi Türkçe tıp eserlerinin 15. yüzyılda artması, bilginin bir azınlık diliyle değil, toplumun konuştuğu dille üretilmesini sağlamıştır. Bu, bilimin millileşmesi ve tabana yayılması sürecidir.\"</i><br><br><b>Türkçe tıp eserlerinin yazılmasının bilimsel sonucu nedir?</b>",
        secenekler: [
            "A) Bilginin dar bir çevrede kalarak kaybolması",
            "B) Tıp bilgisinin halk ve yerel hekimler tarafından daha iyi anlaşılıp yaygınlaşması",
            "C) Arapçanın tamamen yasaklanması",
            "D) Diğer bilim dallarının gerilemesi",
            "E) Hastanelerin sadece Türkçe konuşanlara bakması"
        ],
        cevap: "B) Tıp bilgisinin halk ve yerel hekimler tarafından daha iyi anlaşılıp yaygınlaşması",
        aciklama: "Bilginin halkın diliyle yazılması, bilimsel terminolojinin Türkçeleşmesini ve uzmanlık bilgisinin toplumsal bir nitelik kazanmasını sağlar."
    },
    {
        soru: "<i>\"Fatih'in kütüphaneleri, Bizans ve Avrupa'dan getirilen eserlerin yanı sıra İslam dünyasının klasiklerini de barındırıyordu. Sultan, bu eserleri bizzat okumuş, üzerine notlar almış ve tercümeler yaptırmıştır.\"</i><br><br><b>Fatih'in kütüphane ve tercüme faaliyetlerinin temel amacı nedir?</b>",
        secenekler: [
            "A) Diğer dinlere ait kitapları toplayarak yok etmek",
            "B) Evrensel bilgi birikimini Osmanlı bünyesinde toplayarak entelektüel bir medeniyet merkezi kurmak",
            "C) Sadece kendi yazdığı kitapları kütüphaneye koymak",
            "D) Kitap ticaretini yasaklamak",
            "E) Avrupa'yı teknolojik olarak taklit etmek"
        ],
        cevap: "B) Evrensel bilgi birikimini Osmanlı bünyesinde toplayarak entelektüel bir medeniyet merkezi kurmak",
        aciklama: "Sultanın evrensel bilgi birikimine duyduğu ilgi, Osmanlı Devleti'ni her alanda üstün bir dünya devleti haline getirme vizyonunun bir parçasıdır."
    },
    {
        soru: "<i>\"Osmanlı medreselerindeki 'mülazemet' sistemi, mezunların atanmadan önce staj yaparak beklemesiydi. Bu sayede her göreve, o işin gerektirdiği liyakate sahip en iyi adayların seçilmesi hedefleniyordu.\"</i><br><br><b>Mülazemet sisteminin idari yapıya katkısı nedir?</b>",
        secenekler: [
            "A) Torpil ve kayırmacılığı tamamen ortadan kaldırarak akademik kaliteyi korumak",
            "B) Eğitim süresini kısaltmak",
            "C) Mezunları askere almak",
            "D) Sadece zenginleri atamak",
            "E) Medrese sayılarını azaltmak"
        ],
        cevap: "A) Torpil ve kayırmacılığı tamamen ortadan kaldırarak akademik kaliteyi korumak",
        aciklama: "Düzenli bir bekleme ve denetim süreci olan mülazemet, idari ve hukuki kadroların donanımlı kişilerden oluşmasını sağlayarak sistemin kalitesini korur."
    },
    {
        soru: "<i>\"Bursa ve Edirne medreselerinde yetişen alimlerin çoğu, İstanbul'un fethinden sonra buradaki büyük medreselere geçmişlerdir. Bu hareketlilik, imparatorluk içinde eğitim ve hukuk birliğinin (standardizasyonun) oluşmasını sağlamıştır.\"</i><br><br><b>Akademik hareketliliğin kurumsal sonucu nedir?</b>",
        secenekler: [
            "A) Şehirler arası kültürel farkın artması",
            "B) Devlet genelinde ortak bir eğitim seviyesi ve hukuk anlayışının yerleşmesi",
            "C) İstanbul dışındaki eğitimin kalitesinin düşmesi",
            "D) Alimlerin sadece sarayda kalması",
            "E) Medrese mezunlarının işsiz kalması"
        ],
        cevap: "B) Devlet genelinde ortak bir eğitim seviyesi ve hukuk anlayışının yerleşmesi",
        aciklama: "Alimlerin merkez ile taşra arasında yer değiştirmesi, bilginin ve idari standartların her yerde benzer şekilde uygulanmasını (standardizasyon) sağlar."
    },
    {
        soru: "<i>\"İskân edilen bölgelerde Türkçe konuşan nüfusun yoğunlaşmasıyla birlikte, yerel dillerden Türkçeye ve Türkçeden yerel dillere pek çok kelime geçmiştir. Bu dilsel etkileşim, toplulukların iç içe bir yaşam sürdürdüğünün kanıtıdır.\"</i><br><br><b>Dilsel etkileşim neyi kanıtlar?</b>",
        secenekler: [
            "A) Yerel dillerin tamamen yok olduğunu",
            "B) Toplulukların birbirinden yalıtılmış gettolarda yaşadığını",
            "C) Toplumlar arası yoğun bir iletişim ve kültürel alışverişin yaşandığını",
            "D) Türklerin kendi dillerini unuttuğunu",
            "E) İskânın askeri bir zorlamadan ibaret kaldığını"
        ],
        cevap: "C) Toplumlar arası yoğun bir iletişim ve kültürel alışverişin yaşandığını",
        aciklama: "Karşılıklı kelime alışverişi, toplumların pazar, mahalle ve gündelik hayatta bir arada olduğunu ve birbirlerinin kültürlerini etkilediğini gösterir."
    },
    {
        soru: "<i>\"Osmanlı askeri gücünün lojistik başarısında 'yürükler' kritik rol oynardı. Hayvanlarıyla hareket eden bu gruplar, ordunun et, süt ve nakliye ihtiyacını sefer sırasında yerinden karşılarlardı. Bu, ordunun hareket kabiliyetini artırmıştır.\"</i><br><br><b>Yürüklerin orduya sağladığı temel fayda nedir?</b>",
        secenekler: [
            "A) Sadece kale kuşatmalarında sur yıkmak",
            "B) Ordunun lojistik ve iaşe ihtiyacını esnek ve hızlı bir şekilde karşılamak",
            "C) Sadece yabancı dil tercümanlığı yapmak",
            "D) Deniz savaşlarında kürek çekmek",
            "E) Vergi toplama memuru olarak görev yapmak"
        ],
        cevap: "B) Ordunun lojistik ve iaşe ihtiyacını esnek ve hızlı bir şekilde karşılamak",
        aciklama: "Hareketli bir yaşam süren yürükler, ordunun iaşe (yemek/hayvan) ve taşıma ihtiyaçlarını dinamik bir şekilde desteklemişlerdir."
    },
    {
        soru: "<i>\"İrfan geleneği Osmanlı şiirini (Divan şiiri) derin sembollerle donatmıştır. Gül, bülbül, şarap ve ney gibi kavramlar fiziksel anlamlarının ötesinde; ilahi aşkı, ruhun arayışını ve sabrı temsil ederdi.\"</i><br><br><b>Osmanlı şiirinde kullanılan sembollerin işlevi nedir?</b>",
        secenekler: [
            "A) Şiiri sadece zenginler için anlaşılır kılmak",
            "B) Manevi ve tasavvufi hakikatleri estetik ve dolaylı bir dille ifade etmek",
            "C) Sadece doğa manzaralarını betimlemek",
            "D) Gerçek duyguları gizlemek",
            "E) Şiirdeki anlamı tamamen yok etmek"
        ],
        cevap: "B) Manevi ve tasavvufi hakikatleri estetik ve dolaylı bir dille ifade etmek",
        aciklama: "İrfan temelli edebiyat, soyut manevi gerçekleri günlük hayattan seçilen imgelerle (sembolizm) daha etkileyici bir şekilde sunmayı amaçlar."
    },
    {
        soru: "<i>\"Osmanlı hukukunda 'icma', alimlerin bir mesele üzerindeki görüş birliğini ifade eder. Bu, hukukun kişisel bir keyfiyet olmaktan çıkıp kolektif bir akla dayanmasını sağlar. Alimler arası müzakere, adaletin sağlamlığını oluşturmuştur.\"</i><br><br><b>'İcma' kavramının hukuk sistemine katkısı nedir?</b>",
        secenekler: [
            "A) Kararların hızlanmasını sağlamak",
            "B) Hukuki kararların ortak akıl ve geniş mutabakatla alınmasını sağlayarak adaleti güçlendirmek",
            "C) Padişahın yetkilerini artırmak",
            "D) Hukukun bölgelere göre farklılaşmasını teşvik etmek",
            "E) Eğitim süresini kısaltmak"
        ],
        cevap: "B) Hukuki kararların ortak akıl ve geniş mutabakatla alınmasını sağlayarak adaleti güçlendirmek",
        aciklama: "İcma, bireysel hatayı azaltan ve hukukun toplumsal/bilimsel bir mutabakat üzerinde yükselmesini sağlayan kolektif bir meşruiyet mekanizmasıdır."
    },
    {
        soru: "<i>\"Osmanlı İmparatorluğu'nun kuruluşundan İstanbul'un fethine kadar geçen süreçte ilim ve irfan geleneği, devleti sadece bir askeri güç olmaktan çıkarıp bir medeniyet projesine dönüştürmüştür.\"</i><br><br><b>Bu metnin ana fikri aşağıdakilerden hangisidir?</b>",
        secenekler: [
            "A) Osmanlı'nın sadece savaşçı bir toplum olduğu",
            "B) Askeri başarıların, ilim ve irfanla desteklenerek köklü bir medeniyet inşasına dönüştüğü",
            "C) İstanbul'un fethinden sonra bilimin önemini kaybettiği",
            "D) Beylik döneminin kurumsal açıdan daha üstün olduğu",
            "E) Adalet kavramının sadece fetihler için bir araç olduğu"
        ],
        cevap: "B) Askeri başarıların, ilim ve irfanla desteklenerek köklü bir medeniyet inşasına dönüştüğü",
        aciklama: "Metin; askeri gücün entelektüel (ilim) ve ahlaki (irfan) birikimle bütünleşmesinin bir uygarlık (medeniyet) yaratmadaki kilit rolünü vurgular."
    }
];
window.allTests = window.allTests || {};

window.allTests["test_u2_genel_5"] = [
    {
        soru: "<i>\"Osmanlı Beyliği'nin komşu beylikler arasından sıyrılıp öne çıkması, yalnızca coğrafi konumla açıklanamaz. Osman Bey'in siyasi zekâsı ve insan kaynaklarını yönetme kapasitesi, beyliğini diğerlerinden ayıran etkenin çekirdeğini oluşturmaktadır. Selçuklu mirasından beslenen ama onu aşan bir yönetim anlayışı, erken Osmanlı kimliğinin özgünlüğünü belirlemiştir.\"</i><br><br><b>Köprülü'ye göre Osmanlı Beyliği'nin diğer Anadolu beylikleri arasından sıyrılmasının temel nedeni nedir?</b>",
        secenekler: [
            "A) Osmanlı Beyliği'nin Bizans sınırına en yakın konumda bulunması ve bu sayede fetih fırsatlarını tek başına değerlendirmesi",
            "B) Osman Bey'in siyasi zekâsı ve insan kaynaklarını yönetme kapasitesiyle Selçuklu mirasını aşan özgün yönetim anlayışı",
            "C) Diğer beyliklerin Moğol baskısı altında tamamen ezilmesi ve Osmanlı'nın bu baskıdan korunmuş olması",
            "D) Osmanlı Devleti'nin İslam dünyasındaki halifelik makamını kuruluş aşamasında ele geçirmiş olması",
            "E) Osmanlı Beyliği'nin askeri gücünün diğer tüm beyliklerin toplamından daha büyük olması"
        ],
        cevap: "B) Osman Bey'in siyasi zekâsı ve insan kaynaklarını yönetme kapasitesiyle Selçuklu mirasını aşan özgün yönetim anlayışı",
        aciklama: "Köprülü, coğrafi konumun önemini yadsımamakla birlikte, Osman Bey'in liderlik vasıfları, insan gücünü (alimler, dervişler, beyler) yönetme becerisi ve Selçuklu idari geleneğini yaratıcı biçimde dönüştürmesini başarının anahtarı olarak görür."
    },
    {
        soru: "<i>\"Erken Osmanlı döneminde 'gaza' sadece bir savaş eylemi değil, bir 'kalp kazanma' sürecidir. Fethedilen topraklardaki Hristiyan tebaaya gösterilen adalet ve hoşgörü (istimalet), askeri fethi kalıcı kılan toplumsal bir sözleşmeye dönüşmüştür. Bu yüzden Osmanlı ilerleyişi, kılıç kadar rıza ile de şekillenmiştir.\"</i><br><br><b>İnalcık'ın bu analizine göre istimalet politikasının askeri fetih üzerindeki etkisi hangisidir?</b>",
        secenekler: [
            "A) Askeri operasyonların süresini uzatarak fetihleri yavaşlatmıştır.",
            "B) Fethi sadece bir işgal olmaktan çıkarıp, yerel halkın rızasına dayanan kalıcı bir egemenlik modeline dönüştürmüştür.",
            "C) Gayrimüslimlerin askere alınmasını zorunlu kılmıştır.",
            "D) İslamiyet'in kılıç zoruyla yayılmasını tek yöntem haline getirmiştir.",
            "E) Osmanlı'nın Bizans ile olan tüm diplomatik ilişkilerini kesmesine neden olmuştur."
        ],
        cevap: "B) Fethi sadece bir işgal olmaktan çıkarıp, yerel halkın rızasına dayanan kalıcı bir egemenlik modeline dönüştürmüştür.",
        aciklama: "İnalcık, askeri başarının (kılıç) kalıcı olmasını, yerel halkın adalet ve hoşgörüyle (rıza) sisteme dahil edilmesine bağlar."
    },
    {
        soru: "<i>\"Osmanlı askeri teşkilatında 'kul sistemi'nin (devşirme ve yeniçeri) kurulması, merkezi otoriteyi aşiretlerin ve yerel aristokrat ailelerin etkisinden korumayı amaçlamıştır. Padişah, sadece kendisine bağlı olan bu profesyonel ordu sayesinde rakiplerine karşı mutlak üstünlük sağlamıştır.\"</i><br><br><b>Kul sisteminin Osmanlı devlet yapısındaki birincil siyasi işlevi nedir?</b>",
        secenekler: [
            "A) Türkmen beylerinin yönetimdeki etkinliğini artırmak.",
            "B) Merkezi otoriteyi kişisel sadakate dayalı profesyonel bir güçle tahkim etmek ve rakip odakları dengelemek.",
            "C) Tarımsal üretim üzerindeki denetimi ulemaya devretmek.",
            "D) Hristiyan devletlerle kalıcı barış antlaşmaları imzalamak.",
            "E) Sadece deniz aşırı seferlerde görev yapacak bir sınıf oluşturmak."
        ],
        cevap: "B) Merkezi otoriteyi kişisel sadakate dayalı profesyonel bir güçle tahkim etmek ve rakip odakları dengelemek.",
        aciklama: "Kul sistemi, kökeni aşiret bağlarına dayanmayan, doğrudan sultana bağlı bir sınıf yaratarak merkezi yapının yerel güç odakları karşısında bağımsızlığını ve gücünü korur."
    },
    {
        soru: "<i>\"Bursa'nın fethinden sonra şehre medrese, darüşşifa ve kütüphane inşa edilmesi, Osmanlı'nın salt askeri bir güç olmaktan çıkıp bir kentsel medeniyet nizamı kurma iradesini gösterir. Bu yapılar, Osmanlı fethinin sadece toprak kazanmak değil, o topraklarda kalıcı bir ilim ve kültür iklimi oluşturmak olduğunu kanıtlar.\"</i><br><br><b>Muradiye Külliyesi gibi yapıların inşa edilmesinin medeniyet inşasındaki rolü nedir?</b>",
        secenekler: [
            "A) Şehri sadece düşman saldırılarına karşı korumak.",
            "B) Yerleşim yerlerini kurumsal ve kültürel altyapıyla donatarak fethi kalıcı ve nitelikli bir devlet düzenine dönüştürmek.",
            "C) Ticaret yollarını tamamen kapatarak kenti izole etmek.",
            "D) Sadece gayrimüslim tebaanın eğitim almasını sağlamak.",
            "E) Padişahın hazinesini sadece mimari harcamalar için kullanmak."
        ],
        cevap: "B) Yerleşim yerlerini kurumsal ve kültürel altyapıyla donatarak fethi kalıcı ve nitelikli bir devlet düzenine dönüştürmek.",
        aciklama: "Mimari ve kültürel tesisler, askeri hâkimiyeti toplumsal ve kurumsal bir sürekliliğe dönüştüren medeniyet göstergeleridir."
    },
    {
        soru: "<i>\"1396 Niğbolu Zaferi, Avrupa'da Osmanlı gücüne karşı duyulan korkuyu zirveye taşımıştır. Bu savaşta I. Bayezid'in hızı ve stratejisi, dönemin 'Yenilmez' sayılan Avrupa şövalye ordusunu bozguna uğratmıştır. Bu zafer, Osmanlı'yı İslam dünyasının en büyük askeri hâmisi konumuna getirmiştir.\"</i><br><br><b>Niğbolu Savaşı'nın uluslararası siyaset açısından sonucu nedir?</b>",
        secenekler: [
            "A) Haçlı ittifaklarının Osmanlı'yı Avrupa'dan tamamen atmasıyla sonuçlanmıştır.",
            "B) Osmanlı'nın askeri üstünlüğünün Avrupa tarafından kabul edilmesi ve İslam dünyasında büyük bir saygınlık kazanması.",
            "C) Bizans İmparatorluğu'nun bu tarihten sonra Osmanlı'ya olan vergi borçlarını ödemeyi bırakması.",
            "D) Osmanlı'nın denizcilikte Venedik'i geride bıraktığının kanıtlanması.",
            "E) I. Bayezid'in Ankara Savaşı'na gitmekten vazgeçmesi."
        ],
        cevap: "B) Osmanlı'nın askeri üstünlüğünün Avrupa tarafından kabul edilmesi ve İslam dünyasında büyük bir saygınlık kazanması.",
        aciklama: "Büyük bir Haçlı ordusunun yenilmesi, Osmanlı'nın küresel bir güç olarak tescil edilmesini sağlamış ve Halife tarafından 'Sultan' unvanının onaylanmasına zemin hazırlamıştır."
    },
    {
        soru: "<i>\"Osmanlı hukukunda kadı sicilleri (mahkeme kayıtları), adalet dairesinin taşradaki en şeffaf kanıtıdır. Bu sicillerde zenginden fakire, Müslüman'dan Hristiyan'a herkesin hak arama süreçleri titizlikle kaydedilmiştir. Adaletin kayıt altına alınması, idarenin keyfiyetten hukuka geçişinin belgesidir.\"</i><br><br><b>Kadı sicillerinin (Şer'iye Sicilleri) tarihsel değeri hakkında hangisi söylenebilir?</b>",
        secenekler: [
            "A) Sadece askeri harekatların planlarını içermeleri.",
            "B) Toplumun tüm kesimlerinin hukuki süreçlerini ve gündelik yaşamını yansıtan güvenilir birincil kaynaklar olmaları.",
            "C) Yalnızca padişahların biyografilerini anlatmaları.",
            "D) Bizans idari sistemini övmek amacıyla tutulmaları.",
            "E) Sadece İstanbul merkezli idari kararları kaydetmeleri."
        ],
        cevap: "B) Toplumun tüm kesimlerinin hukuki süreçlerini ve gündelik yaşamını yansıtan güvenilir birincil kaynaklar olmaları.",
        aciklama: "Siciller, toplumun her tabakasının adalete erişimini ve gündelik ekonomik/sosyal hayatını gösteren en temel 'sosyal tarih' belgeleridir."
    },
    {
        soru: "<i>\"Ahi teşkilatının dürüst üretim ve adil paylaşım ilkeleri, Osmanlı şehirlerinde ekonomik istikrarın temelini atmıştır. Kalite denetimi ve narh uygulamasıyla tüketicinin hakkı korunurken, usta-çırak hiyerarşisiyle de mesleki ahlak kuşaktan kuşağa aktarılmıştır. Bu, iktisadın irfani bir disiplinle yönetilmesidir.\"</i><br><br><b>Ahiliğin Osmanlı toplumundaki en önemli ekonomik işlevi hangisidir?</b>",
        secenekler: [
            "A) Üretimi sadece saray ihtiyaçlarıyla sınırlamak.",
            "B) Piyasa düzenini ahlaki ve hukuki kurallarla denetleyerek toplumsal güveni ve ekonomik sürekliliği sağlamak.",
            "C) Dış ticareti tamamen yasaklamak.",
            "D) Sadece Türk kökenli esnafların çalışmasına izin vermek.",
            "E) Vergi toplamayı imkansız hale getirmek."
        ],
        cevap: "B) Piyasa düzenini ahlaki ve hukuki kurallarla denetleyerek toplumsal güveni ve ekonomik sürekliliği sağlamak.",
        aciklama: "Ahilik; üretim kalitesi, fiyat istikrarı ve meslek ahlakı aracılığıyla kentsel ekonomiyi düzenleyen bütüncül bir yapıdır."
    },
    {
        soru: "<i>\"Sahn-ı Seman medreselerinde 'aklî' (felsefe, matematik) ve 'naklî' (tefsir, fıkıh) ilimlerin bir denge içinde okutulması, Osmanlı düşünce dünyasının olgunluğunu yansıtır. Bu medreseler, imparatorluğun entelektüel omurgasını oluşturmuş ve liyakatli bürokratların yetişmesini sağlamıştır.\"</i><br><br><b>Sahn-ı Seman müfredatının özelliği Osmanlı ilim hayatı hakkında ne söyler?</b>",
        secenekler: [
            "A) Eğitimin tamamen pozitif bilimlerden arındırıldığını.",
            "B) Dini inanç ile rasyonel düşünceyi sentezleyen kapsamlı bir eğitim modelinin benimsendiğini.",
            "C) Sadece hukuk alanında uzmanlaşmış kadrolar yetiştirildiğini.",
            "D) Müfredatın sadece Bizans kitaplarından oluştuğunu.",
            "E) Eğitim dilinin sadece Farsça olduğunu."
        ],
        cevap: "B) Dini inanç ile rasyonel düşünceyi sentezleyen kapsamlı bir eğitim modelinin benimsendiğini.",
        aciklama: "Fatih dönemi medreselerinde akli ve nakli bilimlerin bir arada okutulması, Osmanlı'nın rasyonel düşünce ile inancı bütünleştiren vizyonunu kanıtlar."
    },
    {
        soru: "<i>\"Osmanlı askeri lojistiğinde menzil sistemi ve derbent teşkilatı, ordunun ve kervanların damarları gibidir. Yolların güvenliğini sağlayan, köprüleri onaran ve iaşe noktaları kuran bu yerel örgütlenmeler olmasaydı, geniş coğrafyaların kontrolü mümkün olmazdı.\"</i><br><br><b>Yol ve geçit güvenliğinin (derbentçilik) Osmanlı idaresi için önemi nedir?</b>",
        secenekler: [
            "A) Sadece sarayın korunmasını sağlamak.",
            "B) Hem askeri hareketliliği hem de ticari akışı güvence altına alarak devletin coğrafi hâkimiyetini ve ekonomik canlılığını sürdürmek.",
            "C) Yerel halkın seyahat etmesini yasaklamak.",
            "D) Sadece Müslüman tüccarların güvenliğini sağlamak.",
            "E) Anadolu'daki tarımı durdurmak."
        ],
        cevap: "B) Hem askeri hareketliliği hem de ticari akışı güvence altına alarak devletin coğrafi hâkimiyetini ve ekonomik canlılığını sürdürmek.",
        aciklama: "Ulaşım ağlarının güvenliği, merkezi otoritenin taşraya nüfuz etmesi ve ticaret gelirlerinin hazineye akması için hayati önemdedir."
    },
    {
        soru: "<i>\"İskân edilen nüfusun seçiminde devlet, konar-göçer boyları yerleşik hayata geçirmeye çalışarak hem asayişi sağlamış hem de tarımsal üretim alanlarını genişletmiştir. Bu, bir yandan göçebelerin yönetimini kolaylaştırırken, diğer yandan devletin vergi tabanını güçlendirmiştir.\"</i><br><br><b>İskân politikasının göçebeler üzerindeki temel idari hedefi hangisidir?</b>",
        secenekler: [
            "A) Göçebelerin askeri yeteneklerini tamamen yok etmek.",
            "B) Hareketli nüfusu yerleşik düzene geçirerek denetimi artırmak ve onları düzenli vergi veren üreticiler haline getirmek.",
            "C) Onları Anadolu'nun en uzak bölgelerine sürgün etmek.",
            "D) Şehir merkezlerini tamamen göçebelere bırakmak.",
            "E) Hayvancılığı yasaklayarak sadece madencilik yaptırmak."
        ],
        cevap: "B) Hareketli nüfusu yerleşik düzene geçirerek denetimi artırmak ve onları düzenli vergi veren üreticiler haline getirmek.",
        aciklama: "Yerleşik hayata geçiş, devletin nüfusu kayıt altına almasını, asayişi sağlamasını ve üretim-vergi döngüsünü denetlemesini sağlar."
    },
    {
        soru: "<i>\"Sabuncuoğlu Şerefeddin'in tıp eserlerindeki cerrahi minyatürler, bilginin görselleştirilerek eğitimde kullanılmasının öncü örnekleridir. Onun yöntemlerinde görülen deneye dayalı yaklaşım, Osmanlı tıbbının sadece eski metinlerin tekrarı olmadığını, yaşayan ve gelişen bir bilim olduğunu kanıtlar.\"</i><br><br><b>Sabuncuoğlu Şerefeddin'in bilimsel yöntemi hakkında ne söylenebilir?</b>",
        secenekler: [
            "A) Sadece dini metinlere dayalı bir tedavi anlayışı geliştirmiştir.",
            "B) Pratik uygulamaya, gözleme ve eğitimin görselleştirilmesine dayanan modern bilim anlayışının öncüllerinden biridir.",
            "C) Batı Avrupa tıbbını tamamen reddederek izole bir sistem kurmuştur.",
            "D) Sadece bitkisel ilaçlar üzerine yoğunlaşmış, cerrahiyi dışlamıştır.",
            "E) Tıp eğitiminin sadece sarayda verilmesini savunmuştur."
        ],
        cevap: "B) Pratik uygulamaya, gözleme ve eğitimin görselleştirilmesine dayanan modern bilim anlayışının öncüllerinden biridir.",
        aciklama: "Cerrahi müdahaleleri çizimlerle (minyatür) anlatması ve deneysel vurgusu, onun bilimsel metodolojiye verdiği önemi yansıtır."
    },
    {
        soru: "<i>\"İstimalet politikasının bir parçası olarak Osmanlı, Balkanlarda eski feodal beylerin köylülere yüklediği ağır angaryaları (ücretsiz zorunlu işleri) kaldırmış ve vergi oranlarını yasal bir sınıra çekmiştir. Bu, köylülerin Osmanlı'yı bir 'kurtarıcı' olarak görmesini sağlayan mali adaletin ifadesidir.\"</i><br><br><b>Bu durumun Balkanlardaki Osmanlı kalıcılığına etkisi nasıl değerlendirilebilir?</b>",
        secenekler: [
            "A) Köylülerin ekonomik durumunun daha da bozulmasına yol açmıştır.",
            "B) Sosyal ve mali adaleti sağlayarak yerel halkın rızasını kazanmış ve yönetimi meşrulaştırmıştır.",
            "C) Yerel soyluların Osmanlı'ya karşı daha büyük isyanlar başlatmasına neden olmuştur.",
            "D) Vergi gelirlerinin tamamen azalmasına yol açmıştır.",
            "E) Balkanlardan Anadolu'ya büyük bir göç başlatmıştır."
        ],
        cevap: "B) Sosyal ve mali adaleti sağlayarak yerel halkın rızasını kazanmış ve yönetimi meşrulaştırmıştır.",
        aciklama: "Feodal baskıların kaldırılması ve vergi adaleti, halkın yeni yönetimi benimsemesini sağlayan en güçlü 'istimalet' aracıdır."
    },
    {
        soru: "<i>\"Osmanlı vakıfnamelerinde 'hastane hekimlerinin güler yüzlü olması', 'ilaçların taze sunulması' gibi insani şartların yer alması, irfan geleneğinin nezaketini hukuka taşımıştır. Bu, sağlık hizmetinin sadece teknik bir iş değil, ahlaki bir vazife olarak görüldüğünün kanıtıdır.\"</i><br><br><b>Bu vakıf şartlarının Osmanlı sosyal hayatı hakkındaki mesajı nedir?</b>",
        secenekler: [
            "A) Hizmet kalitesinin denetlenemediğini göstermek.",
            "B) İnsana verilen değerin ve hizmet ahlakının yasal bir zorunluluk haline getirildiğini göstermek.",
            "C) Sadece zengin hastaların iyi bakılmasını sağlamak.",
            "D) Hastanelerin ekonomik kazanç amacıyla kurulduğunu kanıtlamak.",
            "E) Din adamlarının hekimlik yapmasını zorunlu kılmak."
        ],
        cevap: "B) İnsana verilen değerin ve hizmet ahlakının yasal bir zorunluluk haline getirildiğini göstermek.",
        aciklama: "Hizmetin ahlaki ve insani kalitesinin vakıf senetlerine (hukuka) geçirilmesi, Osmanlı sosyal devlet anlayışının derinliğini yansıtır."
    },
    {
        soru: "<i>\"1402 Ankara Savaşı sonrasında yaşanan taht mücadeleleri, Osmanlı'nın henüz oturmuş bir veraset sistemine sahip olmadığını göstermiştir. Ancak devlet kurumlarının Fetret Devri boyunca ağır aksak da olsa çalışmaya devam etmesi, beyliğin kurumsal bir devlet iskeletine kavuştuğunu kanıtlamıştır.\"</i><br><br><b>Fetret Devri süreci Osmanlı devlet teşkilatı hakkında hangisini kanıtlar?</b>",
        secenekler: [
            "A) Devletin sadece padişahın şahsına bağlı olduğunu.",
            "B) Hanedan krizine rağmen ayakta kalan kurumsal ve idari bir yapının (bürokrasi, tımar vb.) varlığını.",
            "C) Osmanlı'nın hiçbir zaman tam bağımsız olamadığını.",
            "D) Anadolu birliğinin askeri güçle kurulamayacağını.",
            "E) Siyasi otoritenin ulema tarafından ele geçirildiğini."
        ],
        cevap: "B) Hanedan krizine rağmen ayakta kalan kurumsal ve idari bir yapının (bürokrasi, tımar vb.) varlığını.",
        aciklama: "Merkezi otorite parçalanmış olsa da idari birimlerin işlevini sürdürmesi, Osmanlı'nın salt şahsi değil kurumsal bir devlet olduğunu gösterir."
    },
    {
        soru: "<i>\"Osmanlı'nın fethettiği bölgelerdeki 'baştina' (yerel toprak hakkı) ve diğer eski hakları koruması, mülkiyet güvenliğinin istimaletle ilişkisini belgeler. Halkın en temel varlığını koruyan bir devlet, o halktan vergi ve sadakat talep etme hakkını kendinde görmüştür.\"</i><br><br><b>Yerel hakların korunmasının ekonomik gerekçesi nedir?</b>",
        secenekler: [
            "A) Toprakların mülkiyetini tamamen köylüye devretmek.",
            "B) Ekonomik sürekliliği ve üretim düzenini sarsmadan, güven ortamında vergi akışını sağlamak.",
            "C) Köylülerin şehirlere göç etmesini teşvik etmek.",
            "D) Yerel paraların değerini düşürmek.",
            "E) Sadece askeri personelin toprak sahibi olmasını sağlamak."
        ],
        cevap: "B) Ekonomik sürekliliği ve üretim düzenini sarsmadan, güven ortamında vergi akışını sağlamak.",
        aciklama: "Mülkiyet ve hukuki statü güvencesi, üretim motivasyonunu korur; bu da devletin ekonomik temelinin sarsılmamasını garanti eder."
    },
    {
        soru: "<i>\"Osmanlı İmparatorluğu'nun kuruluşundan itibaren yaya ve müsellem birliklerinin kurulması, askerî gücün aşiret gönüllülerinden profesyonelleşmeye doğru ilk adımıdır. Bu süreç, yerleşik devlet düzenine geçişin askerî alandaki yansımasıdır.\"</i><br><br><b>Askerî profesyonelleşmenin Osmanlı devlet inşasındaki rolü nedir?</b>",
        secenekler: [
            "A) Aşiret liderlerinin siyasi gücünü artırmak.",
            "B) Sürekli ve disiplinli bir orduyla devletin savunma ve genişleme kapasitesini kurumsallaştırmak.",
            "C) Türkmenlerin askerlik yapmasını yasaklamak.",
            "D) Sadece deniz savaşlarına odaklanmak.",
            "E) Orduyu tamamen yabancı paralı askerlere bırakmak."
        ],
        cevap: "B) Sürekli ve disiplinli bir orduyla devletin savunma ve genişleme kapasitesini kurumsallaştırmak.",
        aciklama: "Disiplinli ve düzenli birlikler, beyliğin yerleşik bir devlet aygıtına ve merkeziyetçi bir yapıya evrilmesini hızlandırmıştır."
    },
    {
        soru: "<i>\"Osmanlı döneminde alimlerin 'icazetname'lerinde hocalarının silsilesinin Gazali'ye, İbn Sina'ya veya diğer büyük klasik isimlere dayandırılması, bilginin bir kesinti değil bir gelenek aktarımı olduğunu gösterir. Bu, Osmanlı ilminin evrensel İslam medeniyetiyle olan köklü bağıdır.\"</i><br><br><b>Silsile geleneğinin bilimsel araştırmadaki anlamı nedir?</b>",
        secenekler: [
            "A) Bilginin her kuşakta tamamen değiştirilmesi gerektiğini savunmak.",
            "B) Bilginin meşru bir kaynak ve otorite zinciri içinden gelerek doğruluğunun ve kalitesinin korunmasını sağlamak.",
            "C) Yeni fikirlerin üretilmesini tamamen yasaklamak.",
            "D) Sadece saray tarafından onaylanan alimlerin yetişmesini sağlamak.",
            "E) Bilimin sadece belirli bir coğrafyada kalmasına neden olmak."
        ],
        cevap: "B) Bilginin meşru bir kaynak ve otorite zinciri içinden gelerek doğruluğunun ve kalitesinin korunmasını sağlamak.",
        aciklama: "Silsile, bilginin kaynağını ve doğruluğunu garanti eden manevi ve akademik bir kalite kontrol sistemidir."
    },
    {
        soru: "<i>\"Tımar sistemi içinde beslenen 'cebelü' (atlı asker), devletin en büyük vurucu gücüydü. Ancak bu askerlerin maaşı hazineden çıkmaz, doğrudan toprağın ürününden karşılanırdı. Bu sistem, ekonomiyi orduya, orduyu toprağa bağlayan mükemmel bir dengeydi.\"</i><br><br><b>Metne göre tımar sisteminin mali karakteri hangisidir?</b>",
        secenekler: [
            "A) Devletin hazinesini tamamen sivil işlere ayırması.",
            "B) Hazineden nakit para çıkışı olmadan büyük bir askeri gücü topraktan elde edilen vergiyle finanse etmek.",
            "C) Sipahilerin tüm masraflarının köylüler tarafından nakit olarak ödenmesi.",
            "D) Ordu harcamalarının sadece borçlanmayla karşılanması.",
            "E) Tımar topraklarının orduya satılarak gelir elde edilmesi."
        ],
        cevap: "B) Hazineden nakit para çıkışı olmadan büyük bir askeri gücü topraktan elde edilen vergiyle finanse etmek.",
        aciklama: "Tımar, nakit para kullanımının sınırlı olduğu bir çağda, vergiyi hizmete (asker beslemeye) doğrudan dönüştüren rasyonel bir mali modeldir."
    },
    {
        soru: "<i>\"Osmanlı şehirlerinde vakıf aracılığıyla işletilen dükkânlar, hamamlar ve hanlar; eğitim ve sağlık kurumlarının 'akarı' (gelir kaynağı) olurdu. Bu ekonomik döngü, bilginin ve irfanın paraya bağlı kalmadan sürekliliğini sağlamıştır.\"</i><br><br><b>Vakıf akar (gelir) sisteminin ilim hayatına katkısı nedir?</b>",
        secenekler: [
            "A) Eğitimin kalitesini düşürmesi.",
            "B) İlim ve hayır kurumlarının mali bağımsızlığını ve sürekliliğini yasal bir güvenceye kavuşturması.",
            "C) Sadece Müslümanların ticaret yapmasına izin vermesi.",
            "D) Devletin eğitimden tamamen çekilmesine yol açması.",
            "E) Kütüphanelerdeki kitap sayısını sınırlaması."
        ],
        cevap: "B) İlim ve hayır kurumlarının mali bağımsızlığını ve sürekliliğini yasal bir güvenceye kavuşturması.",
        aciklama: "Mali kaynakların vakıf mülklerine (dükkan, han vb.) bağlanması, kurumların bütçe sarsıntılarından etkilenmeden görevlerini sürdürmesini sağlar."
    },
    {
        soru: "<i>\"Osmanlı'da 'hukuk birliği' yerine 'adalet birliği' esastı. Padişah, tebaasının inancına göre farklı hukuk kurallarına tabi olmasını meşru görmüş; ancak herkesin aynı adalet ölçüsüyle korunmasını emretmiştir. İstimaletin özü bu adalet idealidir.\"</i><br><br><b>Adalet birliği anlayışı Osmanlı yönetiminde hangisine yol açmıştır?</b>",
        secenekler: [
            "A) Herkesin zorla tek bir yasaya tabi tutulmasına.",
            "B) Farklı dini grupların kendi hukuklarını koruduğu ama devletin adalet güvencesi altında olduğu çoğulcu bir yapıya.",
            "C) Hukukun tamamen işlemez hale gelmesine.",
            "D) Hristiyanların mahkemelere girmesinin yasaklanmasına.",
            "E) Sadece askeri hukukun geçerli olmasına."
        ],
        cevap: "B) Farklı dini grupların kendi hukuklarını koruduğu ama devletin adalet güvencesi altında olduğu çoğulcu bir yapıya.",
        aciklama: "İstimalet ve Millet Sistemi, farklı inançların hukuki özerkliğini korurken hepsini padişahın adalet ve himaye şemsiyesi altında birleştirir."
    },
    {
        soru: "<i>\"Osmanlı tıp eğitiminde hekim adaylarının botanik ve eczacılık (ispençiyarlık) öğrenmesi, tedavinin sadece ameliyattan ibaret olmadığını gösterir. Bitkilerin kimyasal etkilerini inceleyen bir hekim profili, Osmanlı biliminin doğa ile kurduğu derin bağı yansıtır.\"</i><br><br><b>Osmanlı tıp eğitiminin içeriği hakkında hangisi söylenebilir?</b>",
        secenekler: [
            "A) Sadece fiziksel egzersizlere odaklanılmıştır.",
            "B) Tıbbi tedavinin biyolojik ve farmakolojik birikimle desteklendiği çok yönlü bir uzmanlık alanı olduğu.",
            "C) Bitkisel tedavinin bilim dışı sayıldığı.",
            "D) Hekimlerin sadece dini dualar öğrendiği.",
            "E) Kimya bilgisinin tıpta kullanılmadığı."
        ],
        cevap: "B) Tıbbi tedavinin biyolojik ve farmakolojik birikimle desteklendiği çok yönlü bir uzmanlık alanı olduğu.",
        aciklama: "Botanik ve eczacılık bilgisinin tıp eğitimine dahil olması, bilimin doğa gözlemi ve analitik veriyle (farmakoloji) beslendiğini kanıtlar."
    },
    {
        soru: "<i>\"Erken Osmanlı döneminde bir kalenin fethiyle birlikte, kale içindeki kilisenin mülkleri korunmuş ve ayinlerine izin verilmiştir. Bu pratik, gazi ruhunun 'yok edici' değil, 'yönetici ve koruyucu' bir karakter taşıdığını gösterir. İstimalet, gaza ile çelişmez; onu tamamlar.\"</i><br><br><b>Gaza ve istimalet arasındaki ilişki metne göre nasıldır?</b>",
        secenekler: [
            "A) Gaza ve istimalet birbirini dışlayan zıt kavramlardır.",
            "B) Gaza askeri fethi sağlarken, istimalet bu fethin ahlaki ve idari olarak kalıcılığını (koruyuculukla) inşa eder.",
            "C) İstimalet, gaza yapılmasını engellemiştir.",
            "D) Gaza sadece yağma için yapılan bir eylemdir.",
            "E) Kilise mülklerinin korunması askeri bir hatadır."
        ],
        cevap: "B) Gaza askeri fethi sağlarken, istimalet bu fethin ahlaki ve idari olarak kalıcılığını (koruyuculukla) inşa eder.",
        aciklama: "Metin, gaza ve istimaletin birbirini tamamlayan, fethin hem askeri hem de sosyal başarısını sağlayan iki boyut olduğunu vurgular."
    },
    {
        soru: "<i>\"Osmanlı'nın Anadolu'daki rakip beylikleri ilhak ederken 'satın alma' (örn: Hamidoğulları) veya 'evlilik' (örn: Germiyanoğulları) yollarına başvurması, siyasi pragmatizmin somut örnekleridir. Osmanlı yönetimi, kılıç kullanmak yerine diplomasiyi tercih ederek hem kan dökülmesini engellemiş hem de kaynaklarını korumuştur.\"</i><br><br><b>Bu diplomatik yöntemlerin Osmanlı büyümesine katkısı nedir?</b>",
        secenekler: [
            "A) Osmanlı'nın askeri zayıflığını göstermiştir.",
            "B) Anadolu'da birliği sağlarken askeri maliyeti düşürmüş ve siyasi rızayı ön plana çıkarmıştır.",
            "C) Beyliklerin Osmanlı'yı ciddiye almamasına neden olmuştur.",
            "D) Sadece toprak kaybına yol açmıştır.",
            "E) Osmanlı'nın gazi kimliğini tamamen bitirmiştir."
        ],
        cevap: "B) Anadolu'da birliği sağlarken askeri maliyeti düşürmüş ve siyasi rızayı ön plana çıkarmıştır.",
        aciklama: "Diplomatik yollarla toprak kazanmak, devletin kaynaklarını tasarruflu kullanmasını sağlar ve beylik halkının Osmanlı idaresine daha yumuşak bir geçiş yapmasına imkân tanır."
    },
    {
        soru: "<i>\"Osmanlı irfan geleneğinde 'hak ve hukuk' sadece insanlar için değil, mülk edilen 'eşya' ve 'mekan' için de geçerliydi. Bir binanın pencerelerinin komşu evin mahremiyetini bozmaması kuralı, mimarinin ahlaki bir zemin üzerine oturtulduğunun kanıtıdır. Şehir, edep üzerine kurulmuştur.\"</i><br><br><b>Mahremiyet kurallarının mimariye etkisi neyi gösterir?</b>",
        secenekler: [
            "A) Şehirlerin plansız büyüdüğünü.",
            "B) Sosyal etik ve bireysel hakların (mahremiyet) mimari tasarımı belirleyen temel unsurlar olduğunu.",
            "C) İnsanların birbiriyle görüşmesinin yasaklandığını.",
            "D) Binaların sadece gösteriş için yapıldığını.",
            "E) Mimari estetiğin hiç önemsenmediğini."
        ],
        cevap: "B) Sosyal etik ve bireysel hakların (mahremiyet) mimari tasarımı belirleyen temel unsurlar olduğunu.",
        aciklama: "Komşu hakları ve mahremiyet gözetilerek yapılan mimari, irfan geleneğinin toplumsal huzur ve saygı idealinin fiziksel formudur."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmet'in kütüphanelerindeki kitapların kenarlarına kendi el yazısıyla düştüğü notlar, onun sadece bir hâmi değil, bir 'eleştirel okur' olduğunu gösterir. Sultanın bu entelektüel derinliği, sarayı bir bilim akademisine dönüştürmüştür.\"</i><br><br><b>Padişahın kitaplar üzerine notlar alması bilim hayatı açısından neyi simgeler?</b>",
        secenekler: [
            "A) Kitapların tahrif edildiğini.",
            "B) Siyasi iktidarın bilimsel faaliyetlerle bizzat, entelektüel düzeyde ilgilendiğini ve bilginin sarayda saygı gördüğünü.",
            "C) Kütüphanelerin bakımsız kaldığını.",
            "D) Sadece askeri konulara ilgi duyulduğunu.",
            "E) Sultanın alimlere güvenmediğini."
        ],
        cevap: "B) Siyasi iktidarın bilimsel faaliyetlerle bizzat, entelektüel düzeyde ilgilendiğini ve bilginin sarayda saygı gördüğünü.",
        aciklama: "Hükümdarın bilginin üretimine ve eleştirisine bizzat katılması, devletin 'kültür ve bilim' kimliğini en üst düzeyde onayladığını gösterir."
    },
    {
        soru: "<i>\"Osmanlı medreselerindeki 'muid'ler (asistanlar), talebenin hocadan aldığı dersi tekrar etmesini ve tartışmasını organize ederdi. Bu yöntem, bilginin yüzeysel ezberlenmesini değil, mantıksal olarak sindirilmesini hedefliyordu. Bilgi, 'aktif öğrenme' ile kalıcı hale geliyordu.\"</i><br><br><b>Muidlerin eğitimdeki asıl katkısı hangisidir?</b>",
        secenekler: [
            "A) Sadece devamsızlık kayıtlarını tutmak.",
            "B) Öğrencilerin bilgiyi içselleştirmesini ve mantıksal analiz yeteneği kazanmasını sağlamak.",
            "C) Müderrislerin ders vermesini engellemek.",
            "D) Kitap sayısını azaltmak.",
            "E) Sadece sınavları kontrol etmek."
        ],
        cevap: "B) Öğrencilerin bilgiyi içselleştirmesini ve mantıksal analiz yeteneği kazanmasını sağlamak.",
        aciklama: "Metin; tekrar ve tartışma yoluyla bilginin mantıksal olarak sindirilmesini vurgular, bu da modern anlamda 'aktif öğrenme'ye karşılık gelir."
    },
    {
        soru: "<i>\"Osmanlı'nın Anadolu'daki beylikleri bir araya getirme çabası, zorlayıcı bir imparatorluk inşasından çok, ortak düşmana karşı 'şemsiye güç' olma iddiasına dayanıyordu. Bu strateji, Osmanlı'nın meşruiyetini rakip beyliklerin halkı nezdinde de pekiştirmiştir.\"</i><br><br><b>'Şemsiye güç' iddiası Osmanlı meşruiyetine nasıl katkı sunmuştur?</b>",
        secenekler: [
            "A) Diğer beyliklerin ordularını tasfiye ederek.",
            "B) Bölgesel güvenlik ve birliği sağlayan üst bir otorite imajı çizerek rızaya dayalı katılımı desteklemesi.",
            "C) Sadece para vererek beylikleri satın almasıyla.",
            "D) Anadolu beyliklerinin isimlerini değiştirmesiyle.",
            "E) Moğollarla gizli ittifak kurarak beylikleri korkutmasıyla."
        ],
        cevap: "B) Bölgesel güvenlik ve birliği sağlayan üst bir otorite imajı çizerek rızaya dayalı katılımı desteklemesi.",
        aciklama: "Güvenliği ve birliği sağlayan (şemsiye) rolü, Osmanlı'yı diğer beylikler arasında 'başat ve meşru' lider konumuna taşımıştır."
    },
    {
        soru: "<i>\"İrfan geleneği, Osmanlı toplumsal yapısında 'vakur' (ağırbaşlı) ve 'mütevazı' bir karakter inşa etmiştir. Bir sadrazam ile bir esnafın aynı camide yan yana saf tutması veya aynı imarette yemek yemesi, bu geleneğin sınıfsal kibiri kıran insani boyutudur.\"</i><br><br><b>Manevi geleneklerin toplumsal eşitliğe katkısı nedir?</b>",
        secenekler: [
            "A) Sınıf farklılıklarını daha da derinleştirmesi.",
            "B) Ortak kutsallar ve mekanlar üzerinden toplumsal hiyerarşiyi yumuşatan bir kardeşlik ve tevazu kültürü oluşturması.",
            "C) Zenginleri fakirleşmeye zorlaması.",
            "D) Devlet memurlarının halktan tamamen kopması.",
            "E) Sadece cami ibadetlerini zorunlu kılması."
        ],
        cevap: "B) Ortak kutsallar ve mekanlar üzerinden toplumsal hiyerarşiyi yumuşatan bir kardeşlik ve tevazu kültürü oluşturması.",
        aciklama: "Ortak manevi pratikler, toplumsal statülerin ötesinde bir 'insani paydaşlık' hissi yaratarak sosyal dokuyu güçlendirir."
    },
    {
        soru: "<i>\"Osmanlı medreselerinden mezun olanların 'mülazemet' (staj) sisteminde bekleme süresince farklı şehirleri gezmesi zorunluydu. Bu durum, taşra ile merkezin aynı ilmi dili konuşmasını ve devletin her yerinde aynı adalet anlayışının hakim olmasını sağlamıştır.\"</i><br><br><b>Adayların farklı şehirleri gezmesinin (dolaşım) kurumsal faydası nedir?</b>",
        secenekler: [
            "A) Alimlerin yorulmasını sağlamak.",
            "B) Bilginin ve idari standartların imparatorluk genelinde homojenleşmesini ve kültürel bütünlüğü sağlamak.",
            "C) İstanbul'daki nüfusu azaltmak.",
            "D) Sadece gezginler sınıfı oluşturmak.",
            "E) Alimlerin ticaretle uğraşmasını sağlamak."
        ],
        cevap: "B) Bilginin ve idari standartların imparatorluk genelinde homojenleşmesini ve kültürel bütünlüğü sağlamak.",
        aciklama: "Hareketlilik, bilginin ve idari deneyimin standardize edilmesini sağlayarak imparatorluk genelinde ortak bir 'devlet aklı' oluşturur."
    },
    {
        soru: "<i>\"Osmanlı İmparatorluğu'nun kuruluşundan 1453'e kadar geçen süreç, ilim ve irfanın askeri fetihlerle 'eş zamanlı' ilerlediği bir süreçtir. Orhan Gazi'nin kılıcı fethederken, müderrisin kalemi o fethi kurumsallaştırmış; dervişin gönlü ise toplumsallaştırmıştır.\"</i><br><br><b>Metne göre Osmanlı'nın kalıcılığını sağlayan 'üçlü sacayağı' hangisidir?</b>",
        secenekler: [
            "A) Para, ticaret, ordu.",
            "B) Askeri güç (fetih), kurumsal düzen (ilim/bürokrasi) ve manevi kabul (irfan/toplum).",
            "C) Sadece kılıç gücü, vergi ve toprak.",
            "D) Deniz gücü, müttefikler, surlar.",
            "E) Göç, savaş, barış."
        ],
        cevap: "B) Askeri güç (fetih), kurumsal düzen (ilim/bürokrasi) ve manevi kabul (irfan/toplum).",
        aciklama: "Başarının sırrı; kılıç (ordu), kalem (ilim/idare) ve gönül (irfan/toplumsal rıza) unsurlarının uyumlu bir şekilde birleşmesinde yatmaktadır."
    }
];
window.allTests = window.allTests || {};

window.allTests["klasik_u2_genel_1"] = [
    {
        soru: "<i>\"Alâeddin Keykubad, uç bölgelerindeki Türkmen beylerini hem sınırı korumakla hem de Bizans topraklarına akın düzenlemekle görevlendirdi. Bu beyler, sultanın doğrudan denetiminden uzakta hareket ederek giderek bağımsız siyasi birimler hâline geldiler.\"</i><br><br><b>Selçuklu uç sisteminin Osmanlı beyliğinin ortaya çıkışına zemin hazırlama biçimini açıklayınız. Bir merkezi devletin sınır yönetim politikasının istemeden bağımsız siyasi birimler doğurmasını nasıl yorumlarsınız?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Selçuklu uç sistemi, merkezi otoriteden uzak, geniş hareket serbestisi tanınan bir sınır yönetimidir. Sultan, askeri yük ve sınır güvenliğini beylere devrederek maliyetini düşürür. İstem dışı özerkleşme bağlamında, bu denetim boşluğu beylerin kendi kaynakları ve sadakat ağlarıyla hareket etmelerine zemin hazırlar. Osmanlı bağlantısı açısından, Ertuğrul ve Osman beyler tam da bu uç konumunda faaliyet göstermiş ve Selçuklu zayıfladıkça merkezi denetimden çıkmışlardır. Bu süreç, merkezi devlet ile taşra aktörü arasındaki gerilimin tarihsel bir kriz doğurduğunu gösterir."
    },
    {
        soru: "<i>\"Osman Gazi'nin rüyasında göğsünden çıkan ağacın bütün dünyayı gölgelemesi, ona sultanlık müjdesi olarak yorumlandı. Bu rüya, Osmanlı hanedanının ilahi bir lütufla taçlandırıldığının simgesidir.\"</i><br><br><b>Bu rüya motifini tarihsel bir kaynak olarak nasıl değerlendirirsiniz? Osmanlı kroniklerinde hanedanın meşruiyetini pekiştirmek amacıyla kullanılan bu tür anlatıların işlevini ve sınırlılığını tartışınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Rüya motifinin işlevi, peygamberlere ve velilere atfedilen rüyalar gibi ilahi bir meşruiyet aracı olmasıdır. Kronikçiler çoğunlukla hanedana yakın kişilerdi ve bu anlatılar nesnel tarihten ziyade siyasi bir meşruiyet metni işlevi görür. Sınırlılıklar açısından bu tür pasajlar kuruluşun gerçek nedenlerini gizleyebilir; rüyanın kuruluştan çok sonra yazıya geçirilmesi güvenilirliğini sorgulatır. Ancak dönemin Osmanlı siyasi kültürü ve meşruiyet anlayışı hakkında çok değerli ipuçları taşıması bakımından tarihsel değeri büyüktür."
    },
    {
        soru: "<i>\"Anadolu'nun Türkleşmesi ve İslamlaşması ani bir fetih olmaktan ziyade uzun soluklu bir demografik ve kültürel süreçtir. Göçebe Türkmen boylarının Bizans kırsal alanına yavaş yavaş yerleşmesi, bölgenin dilsel ve dinsel dönüşümünü belirlemiştir.\"</i><br><br><b>Bu tezden hareketle Osmanlı kuruluşunun demografik ve kültürel arka planını değerlendiriniz. 'Uzun soluklu dönüşüm' yaklaşımı, Osmanlı'nın 1299 gibi kesin bir tarih üzerinden kurulduğu anlayışıyla nasıl çelişir ya da onu tamamlar?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Uzun soluklu dönüşüm, Türkmen boylarının 11. yüzyıldan itibaren Anadolu'ya yerleşmesi ve dilsel-dinsel değişimin yüzyıllara yayılması demektir. 1299 tarihi ise sonraki kronikçilerin belirlediği sembolik bir milattır; 'kuruluş' ani bir kararda değil birikimli bir demografik süreçte anlam kazanır. Tamamlayıcılık açısından bu tez, Osmanlı beyliğini köklü bir 'arka plan' ile beslerken, 1299 bu sürecin siyasi pekişme anı olarak okunabilir. Tarihin kesin tarihlerden ziyade süreçler üzerinden okunması gerektiği vurgulanmalıdır."
    },
    {
        soru: "<i>\"Osmanlı hanedanının kökeni hâlâ tartışmalıdır. Bazı erken kronikler Kayı boyuna mensubiyeti öne çıkarırken bu iddia daha sonraki dönemde siyasi amaçlı olarak güçlendirilmiştir. Hanedanın aslında karma etnik kökenlere sahip olabileceği de göz ardı edilmemelidir.\"</i><br><br><b>Hanedan kökeni tartışmasına ilişkin tespitleri değerlendiriniz. Siyasi amaçlarla şekillendirilen 'köken söylemi' ile tarihsel gerçeklik arasındaki ilişkiyi nasıl kurarsınız? Bu tartışmanın Osmanlı devletinin meşruiyet inşası açısından önemi nedir?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Kayı boyu iddiası, Osmanlıların Oğuz kökeninden geldiği anlatısının özellikle 15. yüzyılda (Timur tehlikesi ve sonrasında) pekiştirilmesiyle Türk-İslam siyasi geleneğine uyumu vurgular. Siyasi işlev açısından hanedanın kökenini güçlü bir boya bağlamak, meşruiyeti geriye dönük olarak inşa etmenin stratejisidir. Tarihsel belirsizlik, erken dönem kayıtlarının azlığı ve kroniklerin çelişkili bilgileriyle köken iddiasını güçleştirir. Siyasi meşruiyet ile tarih yazımının iç içe geçtiği ve köken söyleminin işlevsel bir araç olduğu açıklanmalıdır."
    },
    {
        soru: "<i>\"Bizans kaynaklarında 'Atman' ya da 'Otman' olarak geçen kişi, 1302 Bapheus Savaşı'nda Bizans birliklerini kesin olarak yenen bir Türk lideridir. Bu savaş Osmanlı tarihinin ilk kesin belgelenmiş askeri zaferidir.\"</i><br><br><i>\"Osmanlı ve Karasi beylikleri arasındaki rekabet, iki sınır devletinin yayılmacı dinamiğini yansıtmaktadır. Osmanlıların Karasi'yi 1346'da ilhak etmesi yalnızca toprak kazanımı değil, bir deniz kuvvetleri altyapısı ve uzman savaşçı havuzunun devralınması anlamına da gelmektedir.\"</i><br><br><b>Bu iki kanıtı bir arada kullanarak Osmanlı beyliğinin 1302-1346 arasındaki askeri ve siyasi gelişimini analiz ediniz. Bapheus Savaşı'nın Osmanlı'ya kazandırdıkları ile Karasi'nin ilhakının kazandırdıklarını karşılaştırınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Bapheus'un (1302) önemi, Osmanlı'nın Bizans'a karşı ilk belgelenmiş büyük zaferi olması ve hem toprak hem de diğer uç beylerinin dikkatini çekme (sembolik) sonucunu doğurmasıdır. Karasi ilhakı (1346) ise donanma altyapısı ve denizci nüfus devralınmasıyla Osmanlıların Balkanlara geçişine zemin hazırlar (kapasite transferidir). Karşılaştırma yapıldığında; Bapheus askeri meşruiyet sağlarken, Karasi stratejik güç çarpanı olmuştur. 1302-1346 arası, Osmanlı'nın uç beyliğinden bölgesel güce dönüşme sürecidir."
    },
    {
        soru: "<i>\"Atmanlar denen bu Türkler son derece hızlı hareket ediyor, kalabalık köyleri baskına uğratıp ganimet alıyor, ardından gözden kayboluyorlardı. Bizans'ın ağır süvarisine karşı bu akıncı taktikler çok etkili oldu.\"</i><br><br><b>Bizans tarihçisinin tanıklığından hareketle Osmanlıların erken dönem askeri taktiklerini değerlendiriniz. Bu taktiklerin Bizans ordusunun yapısıyla kıyaslandığında neden avantajlı olduğunu açıklayınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Osmanlı taktikleri; hız, baskın, akın ve çekilme döngüsü üzerine kurulu, ganimet odaklı düşük yoğunluklu savaştır ve büyük meydan muharebelerinden kaçınırlar. Bizans'ın yapısal zayıflığı ise; ağır süvari ve savunma kalesi ağırlıklı ordusunun, hızlı akıncılara karşı yavaş tepki veren maliyetli ve hantal bir yapıda olmasıdır. Bu avantaj; Osmanlıların esnek, merkezi olmayan ve motivasyonu yüksek bir kuvvetle savaşmasından kaynaklanmaktadır."
    },
    {
        soru: "<i>\"Orhan Bey fethettiği Bursa'yı başkent yaptı ve burada pazar kurdu, han yaptırdı, dükkânlar açtırdı. Şehri imar etmek suretiyle reayasını memnun etti ve halkın itaatini kazandı.\"</i><br><br><b>Bu bilgilerden hareketle Osmanlıların fethedilen bir şehri idare etme ve halkı yönetme anlayışını tartışınız. Bursa'nın başkent yapılmasının Osmanlı devlet gelişimi açısından anlamını değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Şehir yönetimi anlayışı; ticari altyapı yatırımlarıyla (pazar, han, dükkân) halkın memnuniyetini hedefleyen rasyonel bir meşruiyet stratejisidir. Reaya memnuniyeti, fetih sonrası ekonomik canlılığı sağlayarak direnişi azaltır ve vergi tabanını büyütür. Bursa'nın önemi; Osmanlı'nın salt askeri bir beylikten şehir medeniyetine (yerleşik devlete) geçişinin simgesi olmasıdır. İmar faaliyetleri ile siyasi meşruiyet arasındaki yapısal bağ vurgulanmalıdır."
    },
    {
        soru: "<i>\"1389 Kosova Savaşı, Sırp tarih geleneğinde ulusal bir yenilgi ve trajedi olarak hafızaya kazınmıştır. Oysa tarihsel araştırmalar savaşın sonucunun her iki taraf açısından da muğlak olduğunu ortaya koymaktadır. I. Murad'ın savaş alanında ölmesi, Osmanlı zaferi söylemini karmaşık hale getirmektedir.\"</i><br><br><b>Bu tespitten hareketle 1389 Kosova Savaşı'nın tarih yazımındaki çelişkili yorumlarını değerlendiriniz. Bir tarihin 'ulusal mit' haline gelmesi ile tarihsel gerçekliğin farklılaşmasına başka örnekler de vererek bu durumu açıklayınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Sonucun muğlaklığı; I. Murad'ın ölmesi, Sırp koalisyonunun dağılması ve Yıldırım Bayezid'in tahta geçmesiyle kısa vadede Osmanlı dezavantajlı görünse de uzun vadede Balkan denetimi pekişmiştir. Ulusal mit mekanizmasında, Sırp destanları Kosova'yı ulusal uyanışın simgesine dönüştürmüş, gerçeklik seçici bir hafıza süzgecinden geçmiştir. Manzikert (1071) gibi başka ulusal mit örnekleri verilebilir. Tarihçinin olayları 'kazanan-kaybeden' basitliğinin ötesinde okuması gerektiği belirtilmelidir."
    },
    {
        soru: "<i>\"Çelebi Mehmed'in en büyük başarısı Fetret Dönemi'nin ayrışma ve kriz atmosferinden çıkarak devleti yeniden bütünleştirmesidir. Bu yeniden birleşme, yalnızca askeri zaferlerle değil, yetenekli bir diplomatik denge politikasıyla mümkün olmuştur.\"</i><br><br><b>Bu değerlendirmeden hareketle bir devletin iç savaş sonrası yeniden bütünleşmesinde diplomasi ve askeri güç arasındaki dengeyi tartışınız. Çelebi Mehmed dönemi bu denge açısından nasıl bir model sunmaktadır?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Fetret'in mirası, beyliklerin yeniden bağımsızlık kazanması ve merkezi otoritenin çöküşüdür. Diplomasi boyutunda Çelebi Mehmed, bazı beyleri savaşmadan itaat altına almış, Bizans ve Venedik ile çatışmaktan kaçınmıştır. Askeri boyutta, kardeş rakipleriyle girdiği savaşları destekçileriyle kazanmıştır. Çelebi Mehmed'in 'en az şiddet, en çok denge' prensibini benimseyerek çok cepheli savaş yerine sıralı ve diplomatik bir ittifak stratejisi yürüttüğü açıklanmalıdır."
    },
    {
        soru: "<i>\"Genç sultan, tahta geçer geçmez İstanbul'u almak için planlar yapmaya başladı. Duvarları aştırmak üzere büyük toplar döktürdü, denizde demir zinciri kırmak için gemiler hazırlattı. Bu hazırlıklar, savaşı teknik bir mühendislik sorununa dönüştürüyordu.\"</i><br><br><b>Aktarılan bilgilerden hareketle Fatih Sultan Mehmed'in İstanbul kuşatmasını sadece askeri değil teknik ve lojistik bir sorun olarak ele almasını değerlendiriniz. Bu yaklaşım tarzı onun önceki Osmanlı liderlerinden ne açıdan ayrışmaktadır?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Teknik boyutta, büyük topların dökülmesi ve surların hedeflenmesi, Orta Çağ surlarına karşı devrimci bir teknoloji transferidir. Lojistik boyutta, gemilerin karadan yürütülmesi olağanüstü bir mühendislik ve planlama başarısıdır. Fatih'i farklı kılan yönü, önceki kuşatmaların uzun süreli pasif blokajlara dayanmasına karşın onun teknolojiyi merkeze alarak süreci hızlandırmasıdır. Teknolojik üstünlüğün savaş sonucunu nasıl belirleyebildiği analiz edilmelidir."
    }
];

window.allTests["klasik_u2_genel_2"] = [
    {
        soru: "<i>\"Bizans İmparatorluğu'nun çöküşü ani bir askeri yenilginin değil, iki yüz yıl süren mali, demografik ve siyasi erozyonun sonucudur. 1453'te Konstantinopolis'in düşmesi, çoktan içten çürümüş bir yapının son tescilidir.\"</i><br><br><b>Bu tespitten hareketle Bizans İmparatorluğu'nun çöküşünü tek bir nedenle (Osmanlı fethi) açıklamanın yetersizliğini tartışınız. Bir imparatorluğun çöküşünde iç ve dış etkenlerin birlikteliğini bu örnek üzerinden değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: İç çöküş dinamikleri; mali kriz (ticaret gelirinin Venedik'e geçmesi), nüfus erimesi (veba, göç) ve iç hanedanlık çatışmalarıdır. Dış etkenler; 1204 Haçlı yağmasının yarattığı yıkım ve Osmanlı'nın sürekli baskısıdır. 'Tek neden' tuzağına düşerek sadece Osmanlı'yı görmek, yapısal sebepleri göz ardı eder; Osmanlı, bir çöküşün tek nedeni değil, son tescilcisidir. Büyük tarihsel dönüşümlerin çok nedenli süreçler olduğu vurgulanmalıdır."
    },
    {
        soru: "<i>\"Savaş, toplumun aynasıdır. Bir toplumun nasıl savaştığı; örgütlenme biçimini, değer sistemini ve ekonomik yapısını yansıtır. Osmanlı'nın askeri sistemi bu açıdan okununca, sistemi doğuran toplumsal ve kurumsal dinamikler gün yüzüne çıkmaktadır.\"</i><br><br><i>\"Osmanlı'nın 14-15. yüzyıllardaki askeri başarısı, salt teknoloji ya da sayısal üstünlüğe değil; kurumsal esnekliğe, farklı coğrafya ve düşmanlar karşısında adapte olabilme kapasitesine dayanıyordu.\"</i><br><br><b>Bu iki tezi bir arada kullanarak 14-15. yüzyıl Osmanlı askeri sistemini bütüncül bir analizle değerlendiriniz. Osmanlı askeri sisteminin yansıttığı toplumsal ve kurumsal dinamikleri somut örneklerle ortaya koyunuz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Toplumun aynası olarak Osmanlı ordusu (gaza ideolojisi, tımarlı Türk sipahi ve devşirme Hristiyan yeniçeri bileşimi) toplumsal çoğulculuğu yansıtır. Kurumsal esneklik bağlamında, farklı coğrafyaların farklı taktikler gerektirmesi (Anadolu'da akıncı, Balkanlarda lojistik, İstanbul'da teknik savaş) ve Karasi'den deniz kapasitesi transferi ile ateşli silahların erken benimsenmesi örnek gösterilmelidir. Tımar sistemi toprak-idare bütünleşmesini, devşirme ise toplumsal mobiliteyi kanıtlar."
    },
    {
        soru: "<i>\"Benim yüksek divanom odur ki; divanda vezirler oturur ve devletin işlerini görüşürler. Divan-ı Hümayun'un kararları kanun hükmündedir. Hiçbir vezir divanın kararından kaçınamaz.\"</i><br><br><b>Fatih'in Kanunnamesi'nden alınan bu pasaj, Osmanlı merkezi yönetiminin nasıl işlediğine dair ne söylemektedir? Divan-ı Hümayun'un devlet mekanizması içindeki konumunu ve bu kurumun toplumun farklı kesimleriyle ilişkisini tartışınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Divan'ın yapısı; sadrazam başkanlığında toplanan en yüksek yürütme ve yargı organıdır. Hukuki işlevi; divan kararlarının savaş, barış, maliye ve atamalar gibi alanlarda kesin bağlayıcı olmasıdır. Toplumla ilişkisi; reayanın divana dilekçe sunabilmesi ve bunun halk için teorik bir adalet kanalı (mazlumların şikayet mercii) olmasıdır. Kanunname'nin önemi, kurumsal işleyişi yazılı hukuka bağlayarak keyfi yönetimi sınırlamasıdır."
    },
    {
        soru: "<i>\"Osmanlı vakıfları yalnızca hayır kurumları değil, aynı zamanda devlet politikasının bir uzantısıdır. Vakıf gelirlerinin önemli bir kısmı camiler, medreseler ve imaretlerin işletilmesine harcanmış; bu yapılar fethedilen şehirlerde Osmanlı varlığının fiziksel ve kültürel simgeleri olmuştur.\"</i><br><br><b>Vakıf analizinden hareketle Osmanlı vakıf sisteminin hem hayırseverlik hem de devlet politikası aracı olma özelliğini tartışınız. Vakıfların şehir ekonomisi ve toplumsal yapısındaki işlevini değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Devlet aracı olarak vakıf; yeni fethedilen şehirlere kurulan yapılar Osmanlı kontrolünün kültürel yatırımla pekiştirilmesidir. Ekonomik işlevi; vakıf mülklerinin (dükkân, han) gelirleriyle dini ve sosyal hizmetleri devlet hazinesine yük olmadan finanse etmesidir. Toplumsal işlevi; imaretlerin yemek vermesi, medreselerin eğitim sunması ve hanların barınak sağlamasıyla meşruiyet kazanılmasıdır. Vakfın sadece bireysel hayırseverlik değil kurumsal bir devlet stratejisi olduğu vurgulanmalıdır."
    },
    {
        soru: "<i>\"Osmanlı kadıları hem yargıç hem noter hem de belediye yöneticisi işlevi görüyordu. Şikâyetleri dinliyor, sözleşmeleri onaylıyor, yerel esnafın faaliyetlerini denetliyor, fiyatları belirliyordu. Bu çok işlevlilik, kadıyı taşra yönetiminin vazgeçilmez direği yapıyordu.\"</i><br><br><b>Bu tanımlamadan hareketle Osmanlı adalet sisteminin yerel düzeyde nasıl işlediğini açıklayınız. Kadılık kurumunun modern devlet fonksiyonlarıyla karşılaştırıldığında ne tür benzerlikleri ve farklılıkları barındırdığını tartışınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Kadının çok işlevliliği yargı (mahkeme), noterlik, pazar denetimi (narh) ve yerel idareyi kapsar. Modern karşılaştırmada; bugün hâkim, noter, belediye başkanı ve gıda denetçisi gibi ayrı kurumlara dağılmış işlevleri Osmanlı'da tek kişi yürütmektedir. Farklılık; modern kurumların uzmanlaşmış olmasına karşın kadının tüm bu işlevleri kişisel otoritesinde toplamasıdır (bu hem verimlilik sağlar hem de keyfi yönetim riski taşır). Kadının merkezin taşradaki gözü olduğu açıklanmalıdır."
    },
    {
        soru: "<i>\"Orhan Bey yeni asker tutmak için hazineden maaş bağladı ve bu askerlere 'yaya' adını verdi. Bunlar savaşta yürüyerek giderler, barışta köylere dönerler ve çift sürerlerdi. Böylece devlet hem asker hem çiftçi bulmuş olurdu.\"</i><br><br><b>Aşıkpaşazade'nin aktardığı bu bilgiden hareketle Osmanlıların kuruluş dönemindeki asker istihdam modelini değerlendiriniz. 'Hem asker hem çiftçi' modeli nasıl bir ekonomik mantık içermektedir? Bu modelin sınırlılıkları neler olabilir?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Yaya/müsellem sistemi; barışta tarım yapan, savaşta devlete hizmet eden yarı profesyonel bir kuvvettir. Ekonomik mantığı; devletin her savaşçı için sürekli maaş ödemekten kurtulması, düşük maliyetli asker gücü sağlanırken tarımsal üretimin korunmasıdır. Sınırlılıkları; yarı zamanlı askerlerin tam seferberlik hızına ve profesyonelliğine ulaşamaması, uzun seferlerde tarım faaliyetlerinin aksaması ve imparatorluğun büyümesiyle bu modelin yetersiz kalmasıdır (daha sonra kapıkuluna geçilecektir)."
    },
    {
        soru: "<i>\"Osmanlı kara ve deniz kuvvetleri arasındaki eşgüdüm sorunu, imparatorluğun genişleme sürecinde yapısal bir zayıflık olarak belirmiştir. Karadaki tımar sistemi ile deniz kuvvetleri finansmanı farklı mantıklar üzerine kurulmuştu.\"</i><br><br><i>\"Osmanlı'nın erken dönemde Bizans ve Ceneviz ticaret ağlarıyla ilişkisi yalnızca çatışmadan ibaret değildi. Ticaret anlaşmaları imzalandı, Cenevizli tüccarlar Osmanlı limanlarına erişim hakkı elde etti. Bu ticari işbirliği Osmanlı gelirlerine önemli katkı yaptı.\"</i><br><br><b>Bu iki tespiti bir arada kullanarak Osmanlı'nın 14-15. yüzyıllarda askeri ve ticari deniz politikasının birbiriyle nasıl çeliştiğini ya da bütünleştiğini analiz ediniz. Kara merkezli tımar sistemi ile deniz ticaretinin farklı mantıklar üzerine kurulmasının doğurduğu yapısal gerilimleri değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Yapısal gerilim; tımar sistemi kara odaklıdır ve toprak gelirine dayanır, ancak deniz kuvvetleri bu mantıkla finanse edilemez, ayrı bütçe ve donanım gerektirir. Bütünleşme; erken Osmanlı'nın pragmatik bir denge kurarak Cenevizlilerle yaptığı ticaret anlaşmalarıyla elde ettiği gümrük gelirlerinin deniz gücü yatırımını desteklemesi ve Karasi ilhakı ile denizcilik altyapısı kazanılmasıdır. Eşgüdüm açığı, bazı deniz operasyonlarında yaşanan gecikmeleri ve devletin yapısal adaptasyon çabasını gösterir."
    },
    {
        soru: "<i>\"Osmanlı siyasi kültürü, gücü salt zor ile değil rıza ve meşruiyet üretimi ile pekiştirmiştir. Bu rızanın üretilmesinde ulemânın, dervişlerin ve vakıfların işlevsel rolleri vardı.\"</i><br><br><i>\"Osmanlı'nın siyasi istikrarı, kurumsal çeşitlilik üzerine kuruluydu. Divan, medrese, vakıf ve tımar sistemi birbirini dengeleyen ve bütünleyen kurumlar olarak işlev gördü.\"</i><br><br><b>Bu perspektifleri kullanarak Osmanlı siyasi istikrarının 14-15. yüzyıllarda nasıl inşa edildiğini analiz ediniz. 'Rıza üretimi' ve 'kurumsal denge' kavramlarını kullanarak hukuk, eğitim, din ve ordu kurumlarının birbirini nasıl tamamladığını gösteriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Rıza üretimi bağlamında, ulema meşruiyet sağlar, dervişler halk tabanını besler, vakıflar sosyal yatırımla halkın rızasını kazanır (salt askeri zorbalık değil). Kurumsal denge bağlamında; Divan (yönetim/yargı), medrese (hukuk/eğitim), vakıf (sosyal/ekonomi) ve tımar (ordu/toprak) birbirini dengeler. Medrese kadı yetiştirirken divan yasal çerçeve sağlar, tımar vergi tabanını korurken vakıf eğitimi finanse eder. Bu sofistike devlet yapısı Osmanlı'yı rakiplerinden ayıran bir özgünlüktür."
    },
    {
        soru: "<i>\"Devşirme sistemi yalnızca bir asker yetiştirme mekanizması değil, aynı zamanda Hristiyan Balkan nüfusundan Osmanlı yönetici sınıfı üretmenin özgün bir yoludur. Devşirilen çocuklar hem din değiştiriyor hem de toplumsal olarak yukarı çıkıyordu; bu onların bakış açısından bir imkân olarak görülebilir.\"</i><br><br><b>Devşirme sistemine ilişkin bu çok boyutlu değerlendirmeyi tartışınız. Devşirme pratiğini hem Osmanlı devletinin perspektifinden hem de ailesinden koparılan Hristiyan çocukların perspektifinden analiz ederek sistemin işlevlerini açıklayınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Osmanlı devleti perspektifinden, hanedana bağlı, yerel ailevi bağları olmayan profesyonel bir yönetici-asker sınıfı yaratarak merkezi otoriteyi güvenceye almak amaçlanır. Çocuk/aile perspektifinden, zorla aileden koparılma ve kültürel kopuşun travmasına karşılık; sistemin özgürlük, yüksek eğitim ve devletin en üst kademelerine kariyer imkânı sunması gibi bir paradoks barındırır. Öğrenci, sistemin dönemin şartlarında bir toplumsal yükselme kanalı olarak nasıl işlediğini empati ve eleştirel bir dengeyle sunmalıdır."
    },
    {
        soru: "<i>\"Osmanlıların Bulgaristan'ı ilhak süreci hem askeri hem de demografik boyutlar içeriyordu. Bazı Bulgar şehirleri teslim olmayı seçerek yerel kurumsallığını korudu; bazıları ise direndi ve farklı bir muameleyle karşılaştı. Osmanlı iskân politikası bu iki kategoride belirgin biçimde ayrışmaktadır.\"</i><br><br><b>Bu tespitten hareketle Osmanlı'nın Bulgar topraklarını ilhak sürecinde teslim olan ve direnen yerleşim birimlerine uyguladığı farklı politikaları karşılaştırınız. Bu ayrımın Osmanlı iskân ve istimalet anlayışıyla ilişkisini değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Teslim olan birimlerde istimalet politikası uygulanarak kilise mülkiyeti ve yerel özerklik kısmen korunmuş, yerel aristokrasi tasfiye edilmemiş ve Türkmen yerleşimi sınırlı tutulmuştur. Direnen birimlerde ise mülklere el konulmuş, yerli yönetici sınıf değiştirilmiş ve yoğun bir nüfus sürgünü/iskânı uygulanmıştır. Osmanlı, bu ayrımla hem yönetim maliyetini düşürmüş hem de diğer bölgelere 'teslim olmanın avantajını' göstererek direnişi caydıran pragmatik bir strateji izlemiştir."
    }
];

window.allTests["klasik_u2_genel_3"] = [
    {
        soru: "<i>\"Fatih Sultan Mehmed İstanbul'u fethettikten sonra şehri yeniden imar etmek için Anadolu ve Rumeli'den zorla nüfus nakli gerçekleştirdi. Bu 'İstanbul sürgünleri' hem Müslüman hem de Hristiyan ve Yahudi aileleri kapsıyordu. Fatih'in hedefi, şehri ekonomik açıdan hızla canlandırmaktı.\"</i><br><br><b>Aktarılan İstanbul'un yeniden imarı politikasından hareketle Osmanlı'nın nüfus mühendisliğini bir ekonomik ve siyasi araç olarak kullanma anlayışını tartışınız. Çok dinli ve çok kültürlü bir şehir yapısının kasıtlı olarak oluşturulmasının uzun vadeli sonuçlarını değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Ekonomik amaç, boşalan şehri hızla nüfusla doldurarak pazar, zanaat ve ticareti canlandırmaktır. Siyasi amaç, farklı toplulukları (Müslüman, Rum, Ermeni, Yahudi) İstanbul'a bağlayarak başkentin meşruiyetini pekiştirmektir (çoğullaştırma politikası). Uzun vadeli sonuçları, bu kasıtlı nüfus mühendisliğinin İstanbul'un yüzyıllarca sürecek kozmopolit yapısının ve bir dünya metropolü olmasının temellerini atması, imparatorluğun insan sermayesini tek merkezde toplayabilmesidir."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed'in Gennadios'u Rum Ortodoks Patriği olarak ataması, Osmanlı'nın Hristiyan tebaa yönetiminde pragmatik bir çözüm benimsediğinin göstergesidir. Patrik cemaat üzerinde hem dini hem yönetsel yetki kullanıyor, böylece Osmanlı devleti Rum cemaatini bu aracılık kanalıyla yönetebiliyordu.\"</i><br><br><b>Rum Patrikhanesi örneğinden hareketle Osmanlı millet sisteminin işleyişini açıklayınız. Bu sistemin Osmanlı açısından avantajlarını ve gayrimüslim topluluklar açısından sunduğu hem fırsatları hem de sınırlılıkları tartışınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Millet sisteminin işleyişi; dini cemaatlerin kendi dini liderleri (patrik/haham) aracılığıyla aile, miras ve din eğitimi meselelerini yönetmesi ve Osmanlı'nın bunlara doğrudan müdahale etmemesidir. Osmanlı'ya avantajı; idari maliyetlerin düşmesi, cemaat önderlerinin düzeni sağlaması ve kültürel direnişin minimize edilmesidir. Gayrimüslimlere fırsatları; özerk iç yönetim ve kendi hukukunu uygulama imkânıdır. Sınırlılıkları ise; cizye yükümlülüğü, meslek/giysi kısıtlamaları ve yasal hiyerarşide (şahitlik gibi) eşitsizliklerdir."
    },
    {
        soru: "<i>\"Osmanlı döneminde İslam'a geçiş süreçleri çoğunlukla tek yönlü bir zorlama değil; toplumsal baskı, ekonomik hesap ve samimi inancın bileşimi biçiminde gerçekleşmiştir. Din değiştirenlerin deneyimleri son derece çeşitlidir ve tek bir neden üzerinden açıklanamaz.\"</i><br><br><b>Din değiştirme süreçlerine ilişkin bu çok nedenli yaklaşımını tartışınız. Osmanlı toplumunda İslam'a geçişi yalnızca 'devlet baskısı' olarak açıklamanın ne gibi tarih yazımı sorunları yarattığını değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Çok nedenlilik; azınlık statüsünün getirdiği toplumsal baskı, vergi avantajları ve kariyer fırsatları gibi ekonomik hesaplar ve samimi dini dönüşümlerin birleşimidir. 'Sadece baskı' olarak açıklamak, dönüştürülen insanların kendi özgür iradelerini ve rasyonel hesaplarını yok sayarak dinamikliği basitleştirir. Tarih yazımı problemi olarak bu tutum, geçmişin tek boyutlu (kurbanlaştırıcı) bir ulusal/dini kimlik siyasetine kurban edilmesi anlamına gelir ve Osmanlı'daki sosyal gerçekliğin karmaşıklığını bastırır."
    },
    {
        soru: "<i>\"Osmanlı'nın ilk alimlerinden Molla Fenari, hem kelam hem fıkıh hem de tasavvuf alanında derin bilgisiyle tanınmaktaydı. Orhan Bey döneminde İznik'te ders verdi; ardından kurulan Bursa medreselerinde müderrislik yaptı ve Osmanlı ilim geleneğinin temel taşlarından biri oldu.\"</i><br><br><b>Taşköprüzade'nin aktardığı Molla Fenari örneğinden hareketle Osmanlı'nın kuruluş döneminde ilim insanlarına verdiği değeri ve bu kişilerin devlet inşasındaki rolünü tartışınız. Molla Fenari'nin farklı alanlarda uzman olmasının Osmanlı ilim anlayışı açısından ne anlam taşıdığını değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: İlim insanlarının devlet inşasındaki rolü; hükümdara fetva ile meşruiyet sağlamaları, eğitimli idari/hukuki bürokratlar yetiştirmeleri ve devletin itibarını artırmalarıdır. Çok alanlı uzmanlık (kelam, fıkıh, tasavvuf), Osmanlı'nın dogmatik Sünni çizgi ile heterodoks halk İslamı arasında denge kurma çabasını ve 'bütünleşik alim' profilini yansıtır. Erken dönem sultanlarının alimleri davet etmesi, ilmin siyasi himaye ile karşılıklı bağımlılık içinde inşa edildiğini gösterir."
    },
    {
        soru: "<i>\"Osmanlı'nın ilk dönemlerinde bilginin yayılması büyük ölçüde medrese kütüphanelerine dayanıyordu. Bu kütüphaneler vakıf gelirleriyle destekleniyor ve kitaplar alimler arasında el yazması olarak çoğaltılıyordu. Matbaanın olmadığı bu dönemde bilgi transferi el yazması ağları üzerinden gerçekleşiyordu.\"</i><br><br><b>Bu tespitten hareketle matbaa öncesi dönemde Osmanlı bilgi ekonomisinin nasıl işlediğini ve bu yapının bilginin yayılma hızını nasıl etkilediğini tartışınız. Vakıf kütüphanelerinin bu sistemdeki merkezi rolünü değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Matbaa öncesi bilgi, medrese çevresindeki alim ağları aracılığıyla elle kopyalanarak yayılırdı; bu, pahalı, yavaş ve elitlere özgü bir transfer şeklidir. Vakıf kütüphaneleri, kitapların korunduğu, erişildiği ve yeni el yazmalarının vakıf bütçesiyle sağlandığı merkezi bilgi aktarım düğümleri olmuştur. Hız ve erişim sorunu; bilginin kopyalanma hızının yavaşlığının kitlelere ulaşmasını daraltarak ilim topluluğunu sınırlı tuttuğunu, ancak vakıfların bu sınırlılığı en aza indiren sürdürülebilir bir sistem kurduğunu gösterir."
    },
    {
        soru: "<i>\"Babai geleneğinin kalıntıları 14. yüzyılda Anadolu'da güçlü bir heterodoks dini hareket olarak yaşamaya devam etti. Bu hareket Osmanlı'nın uç bölgelerinde yoğun takipçi buldu ve Osmanlı'nın ilk dönemde heterodoks tasavvufla ilişkisi son derece yakın oldu.\"</i><br><br><b>Ocak'ın Babai mirası ve Osmanlı ilişkisine dair tespitinden hareketle Osmanlı devletinin ilk dönemde heterodoks dini hareketlere karşı tutumunun neden çok boyutlu ve pragmatik olduğunu değerlendiriniz. Bu ilişki zamanla nasıl değişmiştir?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Erken dönem pragmatizmi; uç bölgelerinde ve göçebe Türkmenler arasında heterodoks dervişlerin nüfuzu güçlüydü. Osmanlı, bu askeri ve demografik desteği kaybetmemek için katı Sünni ortodoksi dayatmak yerine kapsayıcı/pragmatik bir tutum izlemiştir. Zaman içindeki değişim; devlet kurumsallaştıkça, yerleşik düzene geçildikçe ve ulemâ sınıfı güçlendikçe bu hareketler denetim altına alınmış, 15. yüzyılla birlikte Sünni ortodoksinin devlet ideolojisi olarak ağırlık kazandığı bir sürece girilmiştir."
    },
    {
        soru: "<i>\"Fatih Sultan Mehmed, çağının en büyük kitap koleksiyoncularından biriydi. Sarayında Arapça, Farsça ve Türkçe eserler yanı sıra Latince ve Yunanca kitaplar da bulunuyordu. Batılı hümanistlerle yazışması ve Bellini gibi Rönesans sanatçılarını davet etmesi, onu 15. yüzyılın en dikkat çekici 'Renaissance prince'lerinden biri yapmaktadır.\"</i><br><br><b>Bu portre üzerinden Osmanlı ilim ve sanat himayesinin özgün niteliğini değerlendiriniz. Fatih'in hem İslam ilim geleneğine hem de Batılı Rönesans kültürüne aynı anda sahip çıkmasını bir çelişki mi yoksa stratejik bir sentez mi olarak yorumlarsınız?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Osmanlı himayesinin özgünlüğü, sadece İslami değil, dil ve kültür sınırlarını aşan çok yönlü bir ilgiye ve farklı medeniyetlerden sanatçı/alim davetine dayanmasıdır. Bu durum bir çelişki değil; Fatih'in iki kıtanın hakimi olarak evrensel bir imparatorluk kimliği (Kayser-i Rum) inşa etme iradesidir. Bellini gibi sanatçıları davet etmek, Avrupa saraylarına karşı entelektüel bir prestij ve kültürel güç gösterisidir; sanatın meşruiyet ve siyasi hesap aracı olarak kullanıldığını gösterir."
    },
    {
        soru: "<i>\"Osmanlı tarih yazımı yalnızca olayları kaydetmez; aynı zamanda hanedanın meşruiyetini inşa eden ve yeniden üreten bir söylem biçimidir. Tarihçi ile sultan arasındaki ilişki, tarihin hem içeriğini hem de çerçevesini belirlemiştir.\"</i><br><br><i>\"Osmanlı entelektüellerinin siyasi hayatta oynayabileceği roller son derece sınırlıydı. Bürokrasi ve saray, entelektüel bağımsızlığı kısıtlayan bir çerçeve çiziyordu. Bu durum hem bir fırsat hem de bir kısıt kapısıydı.\"</i><br><br><b>Tezcan ve Fleischer'in tespitlerini karşılaştırarak Osmanlı entelektüelinin devlet ile ilişkisini analiz ediniz. Osmanlı ilim ve irfan geleneğinin ürettiği bilginin, devlet denetimi ve himayesi altında şekillenmesinin ne tür güçlü ve sınırlayıcı sonuçlar doğurduğunu değerlendiriniz.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Tezcan, tarih yazımının hanedan meşruiyetini üreten siyasi bir çerçeve olduğunu belirtir. Fleischer ise bürokrasinin ve saray himayesinin entelektüel bağımsızlığı kısıtlayan ancak aynı zamanda onlara bir kariyer fırsatı sunduğunu açıklar. Güçlü sonuçları; devlet himayesi sayesinde devasa külliyelerin, medreselerin ve sanat eserlerinin üretilmesidir. Sınırlayıcı sonuçları; devlet politikasına veya dini dogmalara ters düşebilecek deneysel bilim veya radikal eleştirel düşüncenin kısıtlanması, tek merkezli bir patronaj yapısının entelektüel rekabeti daraltmasıdır."
    },
    {
        soru: "<i>\"Osmanlı'nın erken dönem sınırları, kesin çizgilerle belirlenmiş egemenlik alanları değil; sıvı ve müzakereli bölgelerdi. Bu sınır kültürü, imparatorluğun nasıl büyüdüğünü olduğu kadar nasıl meşruiyet ürettiğini de açıklamaktadır.\"</i><br><br><i>\"Osmanlı toplumunun alt kesimlerini — köylüler, göçebeler, zanaatkarlar — tarihten dışlamamak gerekir. Bu grupların deneyimleri, 'hükümdarlık tarihi'ne indirgenmiş Osmanlı anlatısını derinleştirir ve karmaşıklaştırır.\"</i><br><br><b>Kafadar ve Berktay'ın perspektiflerini bir arada ele alarak Osmanlı'nın kuruluş ve genişleme dönemine 'aşağıdan tarih' perspektifini katmanız halinde tablonun nasıl değişeceğini tartışınız. Sınır bölgelerindeki sıradan insanların deneyimleri hangi tarihsel kaynaklarla gün yüzüne çıkarılabilir?</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: 'Aşağıdan tarih', padişah ve savaşlar yerine sıradan halkın (köylü, göçebe, zanaatkar) deneyimini merkeze alır. Bu perspektif eklendiğinde, sınır bölgelerinin sadece askeri değil, demografik, kültürel ve ekonomik müzakerelerin yaşandığı dinamik ve geçişken bir alan olduğu ortaya çıkar. Kaynaklar olarak; tahrir defterleri (köy/hane verileri), şikayet (mühimme/kadı) sicilleri, vakıf kayıtları, arkeoloji ve sözlü edebiyat izleri gösterilmelidir. Bu yaklaşım resmi hanedan anlatısını kırarak toplumun gerçek katmanlarını görünür kılar."
    },
    {
        soru: "<i>\"Tarih yazımında karşılaştırmalı yaklaşım, birbirine bağlı tarihleri (connected histories) araştırmanın en verimli yollarından biridir. Osmanlı devleti yalnızca Türk-İslam geleneğinin değil, aynı zamanda Bizans, Balkan ve Orta Asya dinamiklerinin bileşkesidir. Bu çok kaynaklı yapı onu hem özgün hem de karşılaştırmalı analize açık kılar.\"</i><br><br><b>Subrahmanyam'ın 'bağlantılı tarihler' kavramını kullanarak Osmanlı devletinin 1299-1453 dönemini Türk-İslam, Bizans, Balkan ve Orta Asya tarihleriyle bağlantısı içinde değerlendiriniz. Bu dönemin hangi alanlarda bu kaynaklardan ne aldığını ve ne kattığını analiz eden bütüncül bir değerlendirme yazınız.</b>",
        cevap: "Öğrencinin cevapta şu unsurları ele alması beklenir: Türk-İslam geleneğinden: Gaza ideolojisi, fıkıh, vakıf ve tımar öncülleri. Bizans'tan: Şehir yönetim pratiği, Divan örgütlenmesi (kısmen), denizcilik ve teknik bilgi. Balkan dinamiklerinden: Hristiyan teba yönetimi (millet sistemi öncülleri), devşirmenin insan kaynağı, yerel feodal yapının tımara dönüşümü. Orta Asya geleneğinden: Aşiret siyasi kültürü (ülüş/kut), süvari savaş kültürü. Osmanlı'nın kattığı özgünlük: Tüm bu parçalı dinamikleri tek bir kurumsal çatı altında harmanlayabilen, çok etnikli/dinli toplumu esnek fetih (istimalet) ile yönetebilen ve askeri genişlemeyi medrese/hukuk derinliğiyle destekleyen evrensel bir imparatorluk sentezi oluşturmasıdır."
    }
];